      const isPostOwner = window.CU && post.userId === window.CU.id;
      const canEdit = isMine;
      const canDel = isMine || isPostOwner || window.CU?.admin;
      const myRxnM = window.CU ? ((c.userReactions||{})[window.CU.id]||'') : '';
