function initSoportePage(){
  // Resetear form si ya fue enviado antes
  document.getElementById('soporteForm').style.display='block';
  document.getElementById('soporteEnviado').style.display='none';
  document.getElementById('soporteTipo').value='';
  document.getElementById('soporteDesc').value='';
  document.getElementById('soporteOtroTxt').value='';
  document.getElementById('soporteOtroWrap').style.display='none';
  document.getElementById('soporteDispositivo').value='';
}

function soporteCheckOtro(){
  const val = document.getElementById('soporteTipo').value;
  document.getElementById('soporteOtroWrap').style.display = val==='otro' ? 'block' : 'none';
}

async function submitSoporte(){
  if(!window.CU){ toast('Tenés que estar logueado para enviar un reporte','err'); return; }
  const tipo = document.getElementById('soporteTipo').value;
  const desc = document.getElementById('soporteDesc').value.trim();
  const otroTxt = document.getElementById('soporteOtroTxt').value.trim();
  const dispositivo = document.getElementById('soporteDispositivo').value;

  if(!tipo){ toast('Seleccioná el tipo de problema','err'); return; }
  if(!desc){ toast('Describí el error antes de enviar','err'); return; }

  const tipoLabel = tipo==='otro' ? ('Otro: '+(otroTxt||'sin especificar')) : document.getElementById('soporteTipo').selectedOptions[0]?.text || tipo;
  const notifText = `🆘 Soporte de @${window.CU.nick||'usuario'}: ${tipoLabel} — "${desc.slice(0,80)}${desc.length>80?'...':''}"`;

  const btn = document.querySelector('#soporteForm button[onclick]');
  if(btn){ btn.disabled=true; btn.textContent='Enviando...'; }

  try {
    // 1. Guardar ticket en colección 'soporte'
    await addDoc(collection(db,'soporte'),{
      uid: window.CU.id,
      nick: window.CU.nick||'',
      av: window.CU.av||'',
      tipo: tipoLabel,
      desc,
      dispositivo,
      time: serverTimestamp(),
      leido: false
    });

    // 2. Notificar al admin usando el sistema de notifs de la app (users/{uid}.notifs)
    // Buscar por nick y por email para asegurarse
    const [byNick, byEmail] = await Promise.all([
      getDocs(query(collection(db,'users'), where('nick','==','ruizgustavo12'))),
      getDocs(query(collection(db,'users'), where('email','==','synxyes@gmail.com')))
    ]);

    const adminIds = new Set();
    byNick.docs.forEach(d=>adminIds.add(d.id));
    byEmail.docs.forEach(d=>adminIds.add(d.id));
    // También buscar por role=='admin' por si hay otros admins
    try {
      const byRole = await getDocs(query(collection(db,'users'), where('role','==','admin')));
      byRole.docs.forEach(d=>adminIds.add(d.id));
    } catch(e){}

    // Enviar a cada admin encontrado (excepto a uno mismo)
    const notifPromises = [];
    adminIds.forEach(adminId => {
      if(adminId !== window.CU.id){
        notifPromises.push(
          updateDoc(doc(db,'users',adminId), {
            notifs: arrayUnion({
              text: notifText,
              time: Date.now(),
              read: false,
              type: 'soporte',
              fromAv: window.CU.av||'',
              fromNick: window.CU.nick||'',
              fromId: window.CU.id
            })
          }).catch(e=>console.warn('No se pudo notificar admin',adminId,e))
        );
      }
    });
    await Promise.all(notifPromises);

    // 3. Mostrar éxito
    document.getElementById('soporteForm').style.display='none';
    document.getElementById('soporteEnviado').style.display='block';

  } catch(e){
    console.error('Error soporte:', e);
    toast('Error al enviar el reporte. Intentá de nuevo.','err');
    if(btn){ btn.disabled=false; btn.textContent='📨 Enviar Reporte'; }
  }
}

