// ===== LIVE STREAMING =====
function _parseLiveUrl(url){
  url = (url||'').trim();
  // YouTube watch
  let m = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
  if(m) return `https://www.youtube.com/embed/${m[1]}?autoplay=1&rel=0`;
  // YouTube live directo
  m = url.match(/youtube\.com\/embed\/([a-zA-Z0-9_-]+)/);
  if(m) return url;
  // Twitch
  m = url.match(/twitch\.tv\/([a-zA-Z0-9_]+)/);
  if(m) return `https://player.twitch.tv/?channel=${m[1]}&parent=${location.hostname}&autoplay=true`;
  return '';
}

async function adminSetLive(activate){
  const url = document.getElementById('liveUrlInput')?.value.trim() || '';
  const title = document.getElementById('liveTitleInput')?.value.trim() || '🔴 Stream en vivo';
  const statusEl = document.getElementById('liveAdminStatus');
  if(activate && !url){ toast('Pegá la URL del stream','err'); return; }
  const embedUrl = activate ? _parseLiveUrl(url) : '';
  if(activate && !embedUrl){ toast('URL no reconocida. Usá YouTube o Twitch','err'); return; }
  try {
    await setDoc(doc(db,'config','live'), { active: activate, url: embedUrl, title, rawUrl: url, updatedAt: serverTimestamp() });
    toast(activate ? '🔴 ¡Live activado!' : '⏹ Live terminado', activate ? 'ok' : 'inf');
    if(statusEl){
      statusEl.style.display = 'block';
      statusEl.style.background = activate ? 'rgba(255,0,0,.1)' : 'var(--bg3)';
      statusEl.style.border = activate ? '1px solid rgba(255,0,0,.3)' : '1px solid var(--border)';
      statusEl.style.color = activate ? '#ff4444' : 'var(--muted)';
      statusEl.textContent = activate ? `🔴 Live activo: ${title}` : '⏹ Sin live activo';
    }
    _applyLiveWidget({ active: activate, url: embedUrl, title });
  } catch(e){ toast('Error al guardar live','err'); console.error(e); }
}

async function loadAdminLive(){
  try {
    const snap = await getDoc(doc(db,'config','live'));
    const data = snap.exists() ? snap.data() : {};
    const statusEl = document.getElementById('liveAdminStatus');
    if(document.getElementById('liveUrlInput')) document.getElementById('liveUrlInput').value = data.rawUrl||'';
    if(document.getElementById('liveTitleInput')) document.getElementById('liveTitleInput').value = data.title||'';
    if(statusEl){
      statusEl.style.display = 'block';
      const active = data.active || false;
      statusEl.style.background = active ? 'rgba(255,0,0,.1)' : 'var(--bg3)';
      statusEl.style.border = active ? '1px solid rgba(255,0,0,.3)' : '1px solid var(--border)';
      statusEl.style.color = active ? '#ff4444' : 'var(--muted)';
      statusEl.textContent = active ? `🔴 Live activo: ${data.title||''}` : '⏹ Sin live activo';
    }
  } catch(e){}
}

function _applyLiveWidget(data){
  const widget = document.getElementById('liveWidget');
  const iframe = document.getElementById('liveIframe');
  const titleEl = document.getElementById('liveWidgetTitle');
  if(!widget || !iframe) return;
  if(data?.active && data.url){
    iframe.src = data.url;
    if(titleEl) titleEl.textContent = data.title || '🔴 Stream en vivo';
    widget.style.display = 'block';
  } else {
    iframe.src = '';
    widget.style.display = 'none';
  }
}

async function listenLive(){
  onSnapshot(doc(db,'config','live'), snap => {
    _applyLiveWidget(snap.exists() ? snap.data() : {});
  });
}
