function loadSavedAccounts(){
  const accounts = JSON.parse(localStorage.getItem('crf4_savedAccounts')||'[]');
  const el = document.getElementById('savedAccountsList');
  if(!el) return;
  if(accounts.length > 0){
    el.style.display = 'block';
    el.innerHTML = `<div style="font-size:.75rem;color:#8b949e;margin-bottom:8px;font-weight:600;">Cuentas guardadas — click para entrar:</div>`
      + accounts.map(a=>`
        <div onclick="quickLogin('${a.email}')" class="fb-saved" style="position:relative;">
          <div class="fb-saved-av">${a.av ? `<img src="${a.av}" style="width:100%;height:100%;object-fit:cover;border-radius:50%;">` : (a.nick||a.email)[0].toUpperCase()}</div>
          <div class="fb-saved-info">
            <div class="fb-saved-nick">${a.nick||a.email} ${a.pw ? '<span style="font-size:.65rem;color:#42b72a;font-weight:600;">● guardada</span>' : ''}</div>
            <div class="fb-saved-email">${maskEmail(a.email)}</div>
          </div>
          <div style="display:flex;align-items:center;gap:8px;">
            <span style="color:#1877f2;font-size:.78rem;font-weight:600;">${a.pw ? '⚡ Entrar' : 'Entrar →'}</span>
            <span onclick="removeSavedAccount('${a.email}',event)" style="color:#666;font-size:.8rem;padding:2px 6px;border-radius:4px;cursor:pointer;" title="Quitar cuenta" onmouseover="this.style.color='#fa3e3e'" onmouseout="this.style.color='#666'">✕</span>
          </div>
        </div>`).join('') + '<div style="height:4px;"></div>';
  } else {
    el.style.display = 'none';
    el.innerHTML = '';
  }
}

function quickLogin(email){
  document.getElementById('lEmail').value = email;
  const accounts = JSON.parse(localStorage.getItem('crf4_savedAccounts')||'[]');
  const acc = accounts.find(a=>a.email===email);
  if(acc && acc.pw){
    try {
      document.getElementById('lPass').value = atob(acc.pw);
      doLogin();
      return;
    } catch(e){}
  }
  document.getElementById('lPass').focus();
}

function saveAccountLocally(email, nick, pw, av){
  let accounts = JSON.parse(localStorage.getItem('crf4_savedAccounts')||'[]');
  const existing = accounts.find(a=>a.email===email);
  const entry = {email, nick, pw: pw ? btoa(pw) : (existing&&existing.pw||''), av: av||existing&&existing.av||''};
  if(existing){ Object.assign(existing, entry); }
  else { accounts.push(entry); }
  if(accounts.length > 5) accounts = accounts.slice(-5);
  localStorage.setItem('crf4_savedAccounts', JSON.stringify(accounts));
}

function removeSavedAccount(email, e){
  e && e.stopPropagation();
  let accounts = JSON.parse(localStorage.getItem('crf4_savedAccounts')||'[]');
  accounts = accounts.filter(a=>a.email!==email);
  localStorage.setItem('crf4_savedAccounts', JSON.stringify(accounts));
  loadSavedAccounts();
}

async function doForgotPassword(){
  // Mostrar modal para ingresar email o nick
  const old = document.getElementById('_forgotModal');
  if(old) old.remove();
  const m = document.createElement('div');
  m.id = '_forgotModal';
  m.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.75);display:flex;align-items:center;justify-content:center;padding:16px;';
  m.innerHTML = `
    <div style="background:#161b22;border:1px solid #30363d;border-radius:16px;padding:28px 24px;max-width:400px;width:100%;box-shadow:0 8px 40px rgba(0,0,0,.5);">
      <div style="font-size:1.5rem;text-align:center;margin-bottom:8px;">🔑</div>
      <div style="font-family:'Orbitron',monospace;font-size:1rem;font-weight:800;color:var(--accent);text-align:center;margin-bottom:6px;">Recuperar contraseña</div>
      <div style="font-size:.82rem;color:var(--muted);text-align:center;margin-bottom:18px;">Ingresá tu email o nick y te enviamos un link para restablecer tu contraseña.</div>
      <input id="_forgotInput" type="text" placeholder="Email o nombre de usuario" style="width:100%;background:#0d1117;border:1px solid #30363d;border-radius:8px;padding:11px 14px;color:#e6edf3;font-family:'Exo 2',sans-serif;font-size:.92rem;outline:none;margin-bottom:10px;" onkeypress="if(event.key==='Enter')_sendForgot()">
      <div id="_forgotErr" style="color:#f85149;font-size:.78rem;text-align:center;margin-bottom:8px;display:none;"></div>
      <div id="_forgotOk" style="color:#3fb950;font-size:.82rem;text-align:center;margin-bottom:8px;display:none;padding:8px;background:rgba(63,185,80,.1);border-radius:6px;border:1px solid rgba(63,185,80,.3);"></div>
      <button onclick="_sendForgot()" id="_forgotBtn" style="width:100%;padding:12px;background:var(--accent);color:#000;border:none;border-radius:8px;font-size:.95rem;font-weight:800;font-family:'Exo 2',sans-serif;cursor:pointer;margin-bottom:10px;transition:opacity .15s;">Enviar link de recuperación</button>
      <button onclick="document.getElementById('_forgotModal').remove()" style="width:100%;padding:10px;background:none;color:var(--muted);border:1px solid #30363d;border-radius:8px;font-size:.85rem;font-weight:600;font-family:'Exo 2',sans-serif;cursor:pointer;">Cancelar</button>
    </div>`;
  m.addEventListener('click', e=>{ if(e.target===m) m.remove(); });
  document.body.appendChild(m);
  setTimeout(()=>{ const inp=document.getElementById('_forgotInput'); if(inp) inp.focus(); }, 100);
}

window._sendForgot = async function(){
  const inp = document.getElementById('_forgotInput');
  const errEl = document.getElementById('_forgotErr');
  const okEl = document.getElementById('_forgotOk');
  const btn = document.getElementById('_forgotBtn');
  let val = inp ? inp.value.trim() : '';
  if(!val){ errEl.textContent='Ingresá tu email o nick'; errEl.style.display='block'; return; }
  errEl.style.display='none'; okEl.style.display='none';
  btn.disabled=true; btn.textContent='Enviando...';
  try {
    let email = val;
    // Si no tiene @ buscar por nick
    if(!val.includes('@')){
      let found = null;
      try {
        const q = await getDocs(query(collection(db,'users'), where('nick','==',val)));
        found = q.docs[0];
      } catch(e2){}
      if(!found){
        try {
          const q2 = await getDocs(query(collection(db,'users'), where('nickLower','==',val.toLowerCase())));
          found = q2.docs[0];
        } catch(e3){}
      }
      if(!found){
        errEl.textContent='Nick no encontrado. Probá con tu email.';
        errEl.style.display='block';
        btn.disabled=false; btn.textContent='Enviar link de recuperación';
        return;
      }
      email = found.data().email;
      if(!email){
        errEl.textContent='No se encontró email para este nick.';
        errEl.style.display='block';
        btn.disabled=false; btn.textContent='Enviar link de recuperación';
        return;
      }
    }
    const { sendPasswordResetEmail } = await import('https://www.gstatic.com/firebasejs/9.23.0/firebase-auth.js');
    await sendPasswordResetEmail(auth, email);
    okEl.textContent='✅ Email enviado a ' + email + '. Revisá tu bandeja de entrada (y el spam).';
    okEl.style.display='block';
    btn.textContent='¡Enviado!';
    setTimeout(()=>{ const m=document.getElementById('_forgotModal'); if(m) m.remove(); }, 4000);
  } catch(e){
    errEl.textContent = e.code==='auth/user-not-found' ? 'No existe una cuenta con ese email.' : 'Error al enviar. Verificá el email.';
    errEl.style.display='block';
    btn.disabled=false; btn.textContent='Enviar link de recuperación';
  }
};

// ===== GALLERY =====
function renderGallery(){
  const grid = document.getElementById('profileGalleryGrid');
  if(!grid || !window.CU) return;
  grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:30px;color:var(--muted);font-size:.85rem;">⏳ Cargando...</div>';
  getDocs(query(collection(db,'posts'), where('userId','==',window.CU.id))).then(snap=>{
    const allImages = snap.docs
      .map(d=>d.data())
      .filter(p=>p.images && p.images.length>0)
      .flatMap(p=>p.images.filter(Boolean));
    if(allImages.length === 0){
      grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:30px;color:var(--muted);font-size:.85rem;">Sin fotos aún. ¡Publica tu primera captura!</div>';
      return;
    }
    window._galleryImages = allImages;
    grid.innerHTML = allImages.map((img,idx)=>
      `<div style="aspect-ratio:1;overflow:hidden;cursor:pointer;border-radius:4px;" onclick="openImgLightbox(window._galleryImages[${idx}],window._galleryImages)">
        <img src="${img}" style="width:100%;height:100%;object-fit:cover;" loading="lazy">
      </div>`).join('');
  }).catch(()=>{
    grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:30px;color:var(--muted);font-size:.85rem;">Error cargando galería</div>';
  });
}

// ===== MULTI-MEDIA UPLOAD =====
let _postMediaFiles = []; // Array of {file, type}

function previewPostMedia(input, type){
  const files = Array.from(input.files);
  if(type === 'image'){
    const remaining = 5 - _postMediaFiles.filter(f=>f.type==='image').length;
    if(files.length > remaining){ toast(`Máximo 5 fotos. Solo se agregarán ${remaining}`,'err'); }
    files.slice(0, remaining).forEach(f => _postMediaFiles.push({file:f, type:'image'}));
  } else {
    _postMediaFiles = _postMediaFiles.filter(f=>f.type!=='video');
    _postMediaFiles.push({file:files[0], type:'video'});
  }
  renderPostMediaPreview();
}

function renderPostMediaPreview(){
  const container = document.getElementById('postMediaPreview');
  const countEl = document.getElementById('postMediaCount');
  if(!_postMediaFiles.length){ container.style.display='none'; return; }
  container.style.display='flex';
  container.innerHTML = _postMediaFiles.map((m,i)=>{
    const url = URL.createObjectURL(m.file);
    if(m.type==='image') return `<div style="position:relative;width:80px;height:80px;border-radius:var(--rs);overflow:hidden;flex-shrink:0"><img src="${url}" style="width:100%;height:100%;object-fit:cover"><button onclick="removePostMedia(${i})" style="position:absolute;top:2px;right:2px;background:rgba(0,0,0,.7);border:none;color:#fff;width:20px;height:20px;border-radius:50%;font-size:.65rem;cursor:pointer;display:flex;align-items:center;justify-content:center;">✕</button></div>`;
    return `<div style="position:relative;width:120px;height:80px;border-radius:var(--rs);overflow:hidden;background:var(--bg3);display:flex;align-items:center;justify-content:center;flex-shrink:0"><video src="${url}" style="width:100%;height:100%;object-fit:cover"></video><button onclick="removePostMedia(${i})" style="position:absolute;top:2px;right:2px;background:rgba(0,0,0,.7);border:none;color:#fff;width:20px;height:20px;border-radius:50%;font-size:.65rem;cursor:pointer;">✕</button><div style="position:absolute;font-size:1.5rem;">▶</div></div>`;
  }).join('');
  const imgs = _postMediaFiles.filter(f=>f.type==='image').length;
  const vids = _postMediaFiles.filter(f=>f.type==='video').length;
  countEl.textContent = `${imgs>0?imgs+' foto(s)':''}${vids>0?(imgs>0?' · ':'')+'1 video':''}`;
}

function removePostMedia(idx){
  _postMediaFiles.splice(idx,1);
  renderPostMediaPreview();
}

function removePostImg(){ _postMediaFiles=[]; renderPostMediaPreview(); }
function previewPostImg(input){ previewPostMedia(input,'image'); }

