async function joinGroup(groupId, groupName){
  if(!window.CU){ toast('Inicia sesión primero','err'); return; }
  const ref = doc(db,'groups',groupId);
  const snap = await getDoc(ref);
  if(!snap.exists()) return;
  const members = snap.data().members || [];
  if(members.includes(window.CU.id)){ toast('Ya sos miembro de este grupo','inf'); return; }
  await updateDoc(ref,{ members:[...members, window.CU.id], memberCount: members.length+1 });
  await loadGroups();
  // Mostrar el grupo con opción de publicar
  showGroupWelcome(groupId, groupName);
}

function showGroupWelcome(groupId, groupName){
  // Mini toast con invitación a publicar
  const ct = document.getElementById('toastCt');
  if(ct){
    const t = document.createElement('div');
    t.className = 'toast ok';
    t.style.cssText='display:flex;flex-direction:column;gap:6px;min-width:220px;';
    t.innerHTML = `<div style="display:flex;gap:8px;align-items:center;"><span>🎣</span><span>¡Bienvenido a <strong>${groupName}</strong>!</span></div>
      <button onclick="this.closest('.toast').remove();openGroupPost('${groupId}','${groupName.replace(/'/g,"\\'")}');"
        style="background:rgba(0,0,0,.3);border:1px solid rgba(255,255,255,.2);color:#fff;border-radius:6px;padding:5px 10px;font-size:.78rem;cursor:pointer;font-family:'Exo 2',sans-serif;font-weight:700;">
        📸 Publicar en el grupo →
      </button>`;
    ct.appendChild(t);
    setTimeout(()=>{ t.style.opacity='0'; t.style.transition='opacity .3s'; setTimeout(()=>t.remove(),300); }, 6000);
  }
}

async function leaveGroup(groupId, groupName){
  if(!window.CU){ toast('Inicia sesión primero','err'); return; }
  if(!confirm(`¿Abandonar el grupo "${groupName}"?`)) return;
  const ref = doc(db,'groups',groupId);
  const snap = await getDoc(ref);
  if(!snap.exists()) return;
  const members = (snap.data().members || []).filter(id=>id!==window.CU.id);
  await updateDoc(ref,{ members, memberCount: Math.max(members.length,0) });
  toast(`Abandonaste "${groupName}"`, 'inf');
  loadGroups();
}

