// ===== YOUTUBE + TIKTOK HELPERS =====
function extractYtId(url){
  if(!url) return null;
  const patterns = [
    /(?:youtube\.com\/watch\?(?:.*&)?v=)([a-zA-Z0-9_-]{11})/,
    /(?:youtu\.be\/)([a-zA-Z0-9_-]{11})/,
    /(?:youtube\.com\/embed\/)([a-zA-Z0-9_-]{11})/,
    /youtube\.com\/shorts\/([a-zA-Z0-9_-]{11})/,
    /youtube\.com\/live\/([a-zA-Z0-9_-]{11})/
  ];
  for(const re of patterns){
    const m = url.match(re);
    if(m) return m[1];
  }
  return null;
}

function extractTikTokId(url){
  if(!url) return null;
  // Format: tiktok.com/@user/video/1234567890
  const m = url.match(/tiktok\.com\/@[^/?]+\/video\/(\d+)/);
  if(m) return m[1];
  // Format: vm.tiktok.com/ZMxxxxxxx/ — short link, return the short code for embed
  const vm = url.match(/(?:vm|vt)\.tiktok\.com\/([A-Za-z0-9]+)/);
  if(vm) return vm[1];
  return null;
}

function isTikTokShortLink(url){
  return url && (url.includes('vm.tiktok.com') || url.includes('vt.tiktok.com'));
}

function isTikTok(url){
  return url && (url.includes('tiktok.com') || url.includes('vm.tiktok.com'));
}

function openPostWithYt(){
  om('mCreatePost');
  setTimeout(()=>{
    const row = document.getElementById('ytInputRow');
    if(row && (row.style.display === 'none' || row.style.display === '')){
      row.style.display = 'block';
    }
    const inp = document.getElementById('ytUrlInput');
    if(inp){ inp.focus(); }
  }, 250);
}

function toggleYtInput(){
  const row = document.getElementById('ytInputRow');
  if(!row) return;
  const isHidden = row.style.display === 'none' || row.style.display === '';
  row.style.display = isHidden ? 'block' : 'none';
  if(isHidden){
    const inp = document.getElementById('ytUrlInput');
    if(inp){ setTimeout(()=>{ inp.focus(); inp.scrollIntoView({behavior:'smooth',block:'center'}); }, 50); }
  }
}

function previewYtEmbed(url){
  const prev = document.getElementById('ytPreview');
  if(!prev) return;
  const ytId = extractYtId(url);
  const ttId = extractTikTokId(url);
  if(ytId){
    prev.style.display='block';
    prev.innerHTML = `<div style="width:100%;aspect-ratio:16/9;border-radius:var(--rs);overflow:hidden;background:#000;">
      <iframe src="https://www.youtube.com/embed/${ytId}?rel=0" frameborder="0" allowfullscreen allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
        style="width:100%;height:100%;display:block;border:none;"></iframe>
    </div><div style="font-size:.72rem;color:var(--green);margin-top:4px;">▶️ YouTube detectado correctamente</div>`;
  } else if(ttId){
    prev.style.display='block';
    prev.innerHTML = `<div style="max-width:340px;margin:0 auto;aspect-ratio:9/16;border-radius:var(--rs);overflow:hidden;background:#000;">
      <iframe src="https://www.tiktok.com/embed/v2/${ttId}" frameborder="0" allowfullscreen allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
        style="width:100%;height:100%;display:block;border:none;"></iframe>
    </div><div style="font-size:.72rem;color:var(--green);margin-top:4px;">🎵 TikTok detectado correctamente</div>`;
  } else if(isTikTok(url) && url.length > 10){
    prev.style.display='block';
    prev.innerHTML='<div style="font-size:.72rem;color:var(--warn);padding:4px;">⚠️ Usá el link completo del video de TikTok (con /video/ID)</div>';
  } else if(url.length > 5){
    prev.style.display='block';
    prev.innerHTML='<div style="font-size:.72rem;color:var(--red);padding:4px;">⚠️ URL no válida. Pegá un link de YouTube o TikTok</div>';
  } else {
    prev.style.display='none';
    prev.innerHTML='';
  }
}

function clearYtInput(){
  const inp = document.getElementById('ytUrlInput');
  const prev = document.getElementById('ytPreview');
  if(inp) inp.value='';
  if(prev){ prev.style.display='none'; prev.innerHTML=''; }
}

