async function renderSuggestedUsers(){
  const el = document.getElementById('amigosSuggList');
  const sidebarEl = document.getElementById('suggestedUsersList');
  if(!el && !sidebarEl) return;
  try {
    const snap = await getDocs(query(collection(db,'users'), orderBy('createdAt','desc'), limit(30)));
    const myId = window.CU?.id;
    const myFriends = window.CU?.friends || [];
    const users = snap.docs
      .map(d=>({id:d.id,...d.data()}))
      .filter(u => u.id !== myId && !myFriends.includes(u.id))
      .sort(()=>Math.random()-0.5)
      .slice(0,8);

    // Cargar presencia de todos en paralelo
    const presMap = {};
    await Promise.all(users.slice(0,8).map(async u => {
      try {
        const pSnap = await getDoc(doc(db,'presence',u.id));
        if(pSnap.exists()){
          const pd = pSnap.data();
          presMap[u.id] = pd.last?.toMillis ? pd.last.toMillis() : (typeof pd.last==='number' ? pd.last : 0);
        }
      } catch(e){}
    }));

    const fmtC = (ts) => {
      if(!ts) return '<span style="color:var(--muted);font-size:.6rem;">Sin datos</span>';
      const diff = Date.now() - ts;
      if(diff < 120000) return '<span style="color:var(--green);font-size:.6rem;font-weight:700;">● En línea</span>';
      const min = Math.floor(diff/60000);
      const h = Math.floor(diff/3600000);
      const d = Math.floor(diff/86400000);
      const txt = min < 2 ? 'Hace un momento' : min < 60 ? 'Hace '+min+' min' : h < 24 ? 'Hace '+h+'h' : 'Hace '+d+' día'+(d>1?'s':'');
      return '<span style="color:var(--muted);font-size:.6rem;">🕐 '+txt+'</span>';
    };

    const cardHTML = (u, small) => {
      const safenick = (u.nick||'').replace(/'/g, "\\'");
      const connHtml = fmtC(presMap[u.id]||0);
      return `<div style="background:var(--bg3);border:1px solid var(--border);border-radius:var(--r);padding:${small?'10px 8px':'14px 10px'};text-align:center;cursor:pointer;transition:border-color .2s;" onclick="openUserProfile('${u.id}','${safenick}');" onmouseover="this.style.borderColor='var(--accent)'" onmouseout="this.style.borderColor='var(--border)'">
        <div style="width:${small?'40px':'52px'};height:${small?'40px':'52px'};border-radius:50%;overflow:hidden;margin:0 auto ${small?'5px':'7px'};border:2px solid var(--border);"><img src="${u.av||getDefaultAv(u.gender||'')}" style="width:100%;height:100%;object-fit:cover;" loading="lazy"></div>
        <div style="font-size:${small?'.7rem':'.78rem'};font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${esc(u.nick||'?')}</div>
        <div style="margin:3px 0;">${connHtml}</div>
        <button onclick="sendFriendRequest('${u.id}','${safenick}','page');event.stopPropagation();" style="margin-top:4px;width:100%;padding:4px;background:var(--accent);border:none;border-radius:var(--rs);color:#000;font-size:.65rem;font-weight:700;cursor:pointer;">+ Agregar</button>
      </div>`;
    };

    if(el) el.innerHTML = users.length
      ? users.map(u=>cardHTML(u, false)).join('')
      : '<div style="font-size:.8rem;color:var(--muted);padding:8px;">Sin sugerencias por ahora</div>';
    if(sidebarEl) sidebarEl.innerHTML = users.slice(0,4).map(u=>cardHTML(u, true)).join('');
  } catch(e){
    if(el) el.innerHTML = '<div style="font-size:.8rem;color:var(--muted);padding:8px;"></div>';
  }
}

