async function renderNewFishers(){
  const el = document.getElementById('newFishersList');
  if(!el) return;
  try {
    const snap = await getDocs(query(collection(db,'users'), orderBy('createdAt','desc'), limit(30)));
    const myId = window.CU?.id;
    const myFriends = window.CU?.friends || [];
    const users = snap.docs
      .map(d=>({id:d.id,...d.data()}))
      .filter(u => u.id !== myId && !window._dismissedFishers.has(u.id))
      .slice(0, 6);
    if(!users.length){ el.innerHTML = '<div style="font-size:.72rem;color:var(--muted);padding:8px 4px;text-align:center;">Sin usuarios por ahora</div>'; return; }

    // Cargar presencia en paralelo
    const presenceMap = {};
    await Promise.all(users.map(async u => {
      try {
        const pSnap = await getDoc(doc(db,'presence',u.id));
        if(pSnap.exists()){
          const pd = pSnap.data();
          const ts = pd.last?.toMillis ? pd.last.toMillis() : (typeof pd.last === 'number' ? pd.last : 0);
          presenceMap[u.id] = ts;
        }
      } catch(e){}
    }));

    // Ordenar por ultima conexion mas reciente
    users.sort((a,b) => (presenceMap[b.id]||0) - (presenceMap[a.id]||0));

    const fmtConn = (ts) => {
      if(!ts) return '<span style="color:var(--muted);font-size:.62rem;">Sin datos</span>';
      const diff = Date.now() - ts;
      if(diff < 120000) return '<span style="color:var(--green);font-size:.62rem;font-weight:700;">● En línea</span>';
      const min = Math.floor(diff/60000);
      const h = Math.floor(diff/3600000);
      const d = Math.floor(diff/86400000);
      const txt = min < 2 ? 'Hace un momento' : min < 60 ? 'Hace '+min+' min' : h < 24 ? 'Hace '+h+'h' : 'Hace '+d+' día'+(d>1?'s':'');
      return '<span style="color:var(--muted);font-size:.62rem;">🕐 '+txt+'</span>';
    };

    let html = '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;padding:2px 0 4px;">';
    users.forEach(u => {
      const isFriend = myFriends.includes(u.id);
      const nick = esc(u.nick||'?');
      const safenick = (u.nick||'').replace(/'/g, "\\'");
      const connHtml = fmtConn(presenceMap[u.id]||0);
      const addBtn = (!isFriend && !isAdminUser(u))
        ? `<button onclick="sendFriendRequest('${u.id}','${safenick}','sidebar');this.textContent='✓ Enviado';this.style.background='var(--bg4)';this.style.color='var(--muted)';this.style.cursor='default';this.disabled=true;event.stopPropagation();" style="width:100%;padding:5px 0;background:rgba(46,196,182,.15);border:1px solid rgba(46,196,182,.4);border-radius:var(--rs);color:var(--accent);font-size:.7rem;font-weight:700;cursor:pointer;font-family:'Exo 2',sans-serif;">+ Agregar</button>`
        : isFriend ? `<div style="font-size:.68rem;color:var(--green);text-align:center;font-weight:700;">✓ Amigos</div>` : '';
      const dismissBtn = `<button onclick="window._dismissedFishers.add('${u.id}');const c=document.getElementById('fisher-card-${u.id}');if(c){c.style.opacity='0';c.style.transform='scale(.92)';c.style.transition='all .2s';setTimeout(()=>{c.remove();const g=document.querySelector('#newFishersList > div');if(g&&g.children.length===0)renderNewFishers();},200);}event.stopPropagation();" style="width:100%;padding:4px 0;background:transparent;border:1px solid var(--border);border-radius:var(--rs);color:var(--muted);font-size:.68rem;font-weight:600;cursor:pointer;font-family:'Exo 2',sans-serif;">Quitar</button>`;
      html += `<div id="fisher-card-${u.id}" style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;overflow:hidden;display:flex;flex-direction:column;transition:border-color .2s;" onmouseover="this.style.borderColor='var(--accent)'" onmouseout="this.style.borderColor='var(--border)'">`
        + `<div onclick="openUserProfile('${u.id}','${safenick}')" style="width:100%;aspect-ratio:1/1;overflow:hidden;cursor:pointer;background:var(--bg3);">`
        + `<img src="${u.av||getDefaultAv(u.gender||'')}" style="width:100%;height:100%;object-fit:cover;display:block;" loading="lazy" onerror="this.src='https://ui-avatars.com/api/?name=${encodeURIComponent(u.nick||'?')}&background=21262d&color=2ec4b6&size=120'">`
        + `</div>`
        + `<div style="padding:7px 7px 8px;display:flex;flex-direction:column;gap:4px;flex:1;">`
        + `<div onclick="openUserProfile('${u.id}','${safenick}')" style="font-size:.75rem;font-weight:700;color:var(--text);cursor:pointer;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${nick}</div>`
        + `<div>${connHtml}</div>`
        + addBtn
        + dismissBtn
        + `</div></div>`;
    });
    html += '</div>';
    el.innerHTML = html;
  } catch(e){ el.innerHTML = '<div style="font-size:.72rem;color:var(--muted);padding:4px;"></div>'; }
}


