// ===== SISTEMA DE VERIFICACIÓN =====

// ── Partículas doradas para perfil verificado ──
let _verifParticleRAF = null;
function _startVerifParticles(canvas){
  if(_verifParticleRAF) return; // ya corriendo
  const cover = document.getElementById('profCover');
  const W = cover.offsetWidth || 800;
  const H = cover.offsetHeight || 300;
  canvas.width = W; canvas.height = H;
  const ctx = canvas.getContext('2d');
  const particles = Array.from({length:38}, ()=>_makeParticle(W,H));
  function step(){
    ctx.clearRect(0,0,W,H);
    particles.forEach((p,i)=>{
      p.y -= p.vy; p.x += p.vx; p.life -= 1;
      if(p.life <= 0){ particles[i] = _makeParticle(W,H); return; }
      const alpha = Math.min(1, p.life/40) * p.maxAlpha;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.fillStyle = p.color;
      ctx.shadowColor = p.color;
      ctx.shadowBlur = 8;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r, 0, Math.PI*2);
      ctx.fill();
      ctx.restore();
    });
    _verifParticleRAF = requestAnimationFrame(step);
  }
  _verifParticleRAF = requestAnimationFrame(step);
}
function _makeParticle(W,H){
  const colors = ['#ffd700','#ffec6e','#ffa500','#fffacd','#f0e68c'];
  return {
    x: Math.random()*W, y: H + Math.random()*20,
    vx: (Math.random()-.5)*.8, vy: .6+Math.random()*1.2,
    r: .8+Math.random()*2.2, life: 60+Math.random()*80,
    maxAlpha: .4+Math.random()*.5,
    color: colors[Math.floor(Math.random()*colors.length)]
  };
}
function _stopVerifParticles(){
  if(_verifParticleRAF){ cancelAnimationFrame(_verifParticleRAF); _verifParticleRAF=null; }
  const canvas = document.getElementById('verifParticles');
  if(canvas){ const ctx=canvas.getContext('2d'); ctx.clearRect(0,0,canvas.width,canvas.height); }
}

