// ===== SEND NOTIFICATION TO ANY USER =====
async function sendNotifToUserStory(uid, text, storyPreview, storyImg, storyId){
  if(!uid || uid===window.CU?.id) return;
  try {
    const notif = {text, time:Date.now(), read:false, storyComment:true,
      storyPreview: storyPreview||'', storyImg: storyImg||'', storyId: storyId||'',
      fromAv: window.CU?.av||'', fromNick: window.CU?.nick||''};
    await updateDoc(doc(db,'users',uid), {notifs: arrayUnion(notif)});
  } catch(e){ console.error('[notifStory ERROR]', e.code, e.message); }
}

async function sendNotifToUser(uid, text){
  if(!uid || uid===window.CU?.id) return;
  try {
    // fromUid incluido para que el receptor pueda identificar al remitente en _chatLastMsgs
    const notif = {text, time:Date.now(), read:false,
      fromUid: window.CU?.id||'',
      fromAv: window.CU?.av||'', fromNick: window.CU?.nick||''};
    await updateDoc(doc(db,'users',uid), {notifs: arrayUnion(notif)});
  } catch(e){ console.error('[notif ERROR]', e.code, e.message); }
}

async function sendNotifToUserWithPost(uid, text, postId, opts){
  if(!uid || uid===window.CU?.id) return;
  try {
    const notif = {text, time:Date.now(), read:false, postId: postId||null,
      fromAv: window.CU?.av||'', fromNick: window.CU?.nick||'',
      postImg: (opts&&opts.postImg)||null,
      postPreviewText: (opts&&opts.postPreviewText)||null};
    await updateDoc(doc(db,'users',uid), {notifs: arrayUnion(notif)});
  } catch(e){ console.error('[notifPost ERROR]', e.code, e.message); }
}

