function openEditPost(pid, text){
  document.getElementById('editPostId').value = pid;
  document.getElementById('editPostText').value = text;
  om('mEditPost');
}
window.openEditPost = openEditPost;

async function saveEditPost(){
  const pid = document.getElementById('editPostId').value;
  const text = document.getElementById('editPostText').value.trim();
  if(!pid){ toast('Error: no se encontró la publicación','err'); return; }
  if(!text){ toast('El texto no puede estar vacío','err'); return; }
  try {
    await updateDoc(doc(db,'posts',pid), {text, edited:true});
    // Actualizar cache local
    if(window._posts){
      const p = window._posts.find(p=>p.id===pid);
      if(p){ p.text = text; p.edited = true; }
    }
    // Actualizar el texto en el DOM sin recargar
    const postEl = document.getElementById('post_'+pid);
    if(postEl){
      const textEl = postEl.querySelector('.post-text');
      if(textEl) textEl.innerHTML = renderCommentText(text);
    }
    cm('mEditPost');
    toast('Publicación editada ✅','ok');
  } catch(e){
    console.error('saveEditPost error:', e);
    toast('Error al editar: ' + (e.message||e), 'err');
  }
}

async function deleteMyPost(pid){
  if(!confirm('¿Eliminar tu publicación?')) return;
  try {
    await deleteDoc(doc(db,'posts',pid));
    // Quitar del cache local inmediatamente
    if(window._posts) window._posts = window._posts.filter(p=>p.id!==pid);
    // Cerrar menú si está abierto
    const menu = document.getElementById('pmenu_'+pid);
    if(menu) menu.style.display='none';
    // Quitar la card del DOM sin recargar todo
    const card = document.getElementById('post_'+pid) || document.querySelector('[data-pid="'+pid+'"]');
    if(card){ card.style.transition='opacity .3s'; card.style.opacity='0'; setTimeout(()=>card.remove(),300); }
    else { renderFeed && renderFeed(); }
    toast('Publicación eliminada','ok');
  } catch(e){ toast('Error al eliminar','err'); }
}

