function swSkillTab(tab) {
  const tabs = { cebo: 'stCebo', cosecha: 'stCosecha', 'señuelos': 'stSenuelos' };
  const panels = { cebo: 'skill-cebo', cosecha: 'skill-cosecha', 'señuelos': 'skill-senuelos' };
  Object.keys(tabs).forEach(k => {
    const btn = document.getElementById(tabs[k]);
    const panel = document.getElementById(panels[k]);
    if (!btn || !panel) return;
    if (k === tab) {
      btn.style.cssText = 'padding:7px 16px;border-radius:100px;font-family:\'Exo 2\',sans-serif;font-size:.82rem;font-weight:700;cursor:pointer;border:1px solid var(--accent);background:rgba(46,196,182,.15);color:var(--accent);';
      panel.style.display = '';
    } else {
      btn.style.cssText = 'padding:7px 16px;border-radius:100px;font-family:\'Exo 2\',sans-serif;font-size:.82rem;font-weight:700;cursor:pointer;border:1px solid var(--border);background:var(--bg3);color:var(--muted);';
      panel.style.display = 'none';
    }
  });
}
window.swSkillTab = swSkillTab;

