  document.getElementById('vfMine').style.cssText = type==='mine'
    ? 'background:rgba(0,198,255,.15);border:1px solid var(--accent);color:var(--accent);padding:6px 16px;border-radius:100px;font-family:\'Exo 2\',sans-serif;font-size:.8rem;font-weight:700;cursor:pointer;'
    : 'background:var(--bg3);border:1px solid var(--border);color:var(--muted);padding:6px 16px;border-radius:100px;font-family:\'Exo 2\',sans-serif;font-size:.8rem;font-weight:700;cursor:pointer;';
