async function saveXPLevels(){
  if(!window.CU || (window.CU.nick !== 'ruizgustavo12' && window.CU.email !== 'synxyes@gmail.com')) return;
  try {
    const rows = document.querySelectorAll('.xp-level-row');
    const levels = Array.from(rows).map(row => ({
      name:  row.querySelector('.xpl-name').value.trim(),
      min:   parseInt(row.querySelector('.xpl-min').value)||0,
      max:   parseInt(row.querySelector('.xpl-max').value)||999,
      color: row.querySelector('.xpl-color').value,
      border:row.querySelector('.xpl-border').value,
    })).filter(l=>l.name);
    if(levels.length < 2){ toast('Necesitás al menos 2 niveles','err'); return; }
    // Sort by min XP
    levels.sort((a,b)=>a.min-b.min);
    await setDoc(doc(db,'config','xpLevels'),{levels});
    XP_LEVELS = levels;
    toast('✅ Niveles de XP guardados','ok');
    renderXPLevelsAdmin();
    renderXPUI();
  } catch(e){ toast('Error: '+e.message,'err'); }
}

