// ===== MÚSICA CON JAMENDO API =====
const JAMENDO_CLIENT_ID = '197c0e16';
let _musicDebounce = null;
let _currentAudio = null;
let _currentTrackId = null;

function debounceMusicSearch(){
  clearTimeout(_musicDebounce);
  const q = (document.getElementById('musicSearchInput').value||'').trim();
  if(!q){
    document.getElementById('musicResults').innerHTML = '';
    document.getElementById('musicSuggestions').style.display = 'block';
    return;
  }
  if(q.length < 2) return;
  document.getElementById('musicResults').innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:20px;color:var(--muted);font-size:.85rem;">🔍 Buscando...</div>`;
  document.getElementById('musicSuggestions').style.display = 'none';
  _musicDebounce = setTimeout(()=>searchDeezer(), 400);
}

async function searchDeezer(){
  const q = (document.getElementById('musicSearchInput').value||'').trim();
  if(!q){ toast('Escribí algo para buscar 🎵','err'); return; }
  const resultsEl = document.getElementById('musicResults');
  const sugEl = document.getElementById('musicSuggestions');
  if(sugEl) sugEl.style.display = 'none';
  resultsEl.innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:30px;color:var(--muted);"><div style="font-size:1.8rem;margin-bottom:8px;animation:spin 1s linear infinite;display:inline-block;">🎵</div><div style="margin-top:8px;">Buscando música...</div></div>`;

  try {
    const url = `https://api.jamendo.com/v3.0/tracks/?client_id=${JAMENDO_CLIENT_ID}&format=json&limit=30&namesearch=${encodeURIComponent(q)}&include=musicinfo&audioformat=mp32&audiodownload_allowed=true`;
    const r = await fetch(url, {signal: AbortSignal.timeout(8000)});
    if(!r.ok) throw new Error('HTTP '+r.status);
    const data = await r.json();
    const tracks = data.results || [];
    if(tracks.length === 0){
      // Try broader search by tags
      const url2 = `https://api.jamendo.com/v3.0/tracks/?client_id=${JAMENDO_CLIENT_ID}&format=json&limit=30&search=${encodeURIComponent(q)}&include=musicinfo&audioformat=mp32&audiodownload_allowed=true`;
      const r2 = await fetch(url2, {signal: AbortSignal.timeout(8000)});
      const data2 = await r2.json();
      const tracks2 = data2.results || [];
      if(tracks2.length) { renderJamendoResults(tracks2); return; }
      resultsEl.innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:30px;color:var(--muted);">
        <div style="font-size:2rem;">🎵</div>
        <div style="margin-top:10px;font-weight:700;">No se encontraron canciones para "<em>${q}</em>"</div>
        <div style="font-size:.8rem;margin-top:6px;">Probá con otro término — Jamendo tiene música indie y libre de derechos</div>
      </div>`;
      return;
    }
    renderJamendoResults(tracks);
  } catch(e){
    console.error('Jamendo error:', e);
    resultsEl.innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:30px;color:var(--muted);">
      <div style="font-size:2rem;">⚠️</div>
      <div style="margin-top:10px;font-weight:700;">Error al conectar con Jamendo</div>
      <div style="font-size:.8rem;margin-top:6px;">Verificá tu conexión e intentá de nuevo</div>
      <button onclick="searchDeezer()" style="margin-top:12px;background:var(--accent);border:none;border-radius:8px;color:#fff;padding:8px 20px;font-weight:700;cursor:pointer;font-family:'Exo 2',sans-serif;">🔄 Reintentar</button>
    </div>`;
  }
}

function renderJamendoResults(tracks){
  const el = document.getElementById('musicResults');
  el.innerHTML = tracks.map(t => {
    const dur = t.duration ? Math.floor(t.duration/60)+':'+String(t.duration%60).padStart(2,'0') : '';
    const safeId = t.id||'';
    const safeTitle = (t.name||'').replace(/'/g,"\'").replace(/"/g,'&quot;');
    const safeArtist = (t.artist_name||'').replace(/'/g,"\'").replace(/"/g,'&quot;');
    const safeAudio = (t.audiodownload||t.audio||'').replace(/'/g,"\'");
    const thumb = t.album_image || t.image || 'https://api.jamendo.com/v3.0/tracks/file/?client_id=197c0e16&id='+t.id+'&imagesize=200';
    return `<div class="music-card" style="cursor:pointer;position:relative;" id="jcard_${safeId}">
      <div style="position:relative;" onclick="playJamendo('${safeId}','${safeTitle}','${safeArtist}','${safeAudio}')">
        <img src="${thumb}" loading="lazy" onerror="this.src='https://usercontent.jamendo.com?type=album&id=${t.album_id}&width=200'" style="width:100%;aspect-ratio:1;object-fit:cover;border-radius:8px 8px 0 0;display:block;background:#1a1a2e;">
        <div id="jplay_${safeId}" style="position:absolute;bottom:6px;right:6px;background:rgba(46,196,182,.9);border-radius:50%;width:36px;height:36px;display:flex;align-items:center;justify-content:center;font-size:1rem;transition:transform .15s;">▶</div>
        ${dur?`<div style="position:absolute;bottom:6px;left:6px;background:rgba(0,0,0,.75);color:#fff;font-size:.6rem;font-weight:700;padding:2px 6px;border-radius:4px;">${dur}</div>`:''}
      </div>
      <div class="music-card-body">
        <div class="music-card-title">${(t.name||'').replace(/</g,'&lt;')}</div>
        <div class="music-card-sub">${(t.artist_name||'').replace(/</g,'&lt;')}</div>
        <div style="font-size:.62rem;color:var(--accent);margin-top:3px;">🎵 Jamendo · Libre de derechos</div>
      </div>
    </div>`;
  }).join('');
}

function playJamendo(trackId, title, artist, audioUrl){
  // Reset previous card button
  if(_currentTrackId){
    const prevBtn = document.getElementById('jplay_'+_currentTrackId);
    if(prevBtn) prevBtn.textContent = '\u25b6';
  }
  if(_currentAudio){ _currentAudio.pause(); _currentAudio.src=''; _currentAudio=null; }

  _currentTrackId = trackId;
  const btn = document.getElementById('jplay_'+trackId);
  if(btn) btn.textContent = '\u23f8';

  const titleEl = document.getElementById('deezerTitleBig');
  const artistEl = document.getElementById('deezerArtistBig');
  const wrap = document.getElementById('musicPlayerWrap');
  if(titleEl) titleEl.textContent = title||'';
  if(artistEl) artistEl.textContent = artist||'';
  if(wrap) wrap.style.display='block';

  // Intentar reproducción directa con múltiples fuentes
  const tryPlay = (urls, index=0) => {
    if(index >= urls.length){
      // Fallback: abrir en Jamendo
      toast('Abriendo en Jamendo...','inf');
      window.open('https://www.jamendo.com/track/'+trackId,'_blank');
      if(btn) btn.textContent='\u25b6';
      return;
    }
    const src = urls[index];
    if(!src){ tryPlay(urls, index+1); return; }
    const audio = new Audio();
    audio.crossOrigin = 'anonymous';
    audio.preload = 'none';
    audio.src = src;
    audio.volume = 0.8;
    const progWrap = document.getElementById('musicProgBar');
    audio.play().then(()=>{
      _currentAudio = audio;
      toast('\u25b6 '+title,'ok');
      if(titleEl) titleEl.textContent = title||'';
      if(artistEl) artistEl.textContent = artist||'';
      audio.onended = ()=>{ if(btn) btn.textContent='\u25b6'; _currentTrackId=null; };
      if(progWrap){ audio.ontimeupdate=()=>{ if(audio.duration) progWrap.style.width=(audio.currentTime/audio.duration*100)+'%'; }; }
      const pauseBtn = document.getElementById('musicPauseBtn');
      if(pauseBtn){
        pauseBtn.onclick = ()=>{
          if(audio.paused){ audio.play(); pauseBtn.textContent='\u23f8'; }
          else { audio.pause(); pauseBtn.textContent='\u25b6'; }
        };
      }
    }).catch(()=>{ tryPlay(urls, index+1); });
  };

  // Fuentes en orden: audiodownload (sin CORS), audio, stream Jamendo CDN
  const sources = [
    audioUrl,
    audioUrl ? audioUrl.replace('https://mp3d.jamendo.com','https://storage.googleapis.com/jamendo') : null,
    `https://mp3d.jamendo.com/?trackid=${trackId}&format=mp32`
  ];
  tryPlay(sources);
}

