function closeMusicPlayer(){
  const wrap = document.getElementById('musicPlayerWrap');
  const iframe = document.getElementById('ytMusicPlayer');
  const audio = document.getElementById('deezerAudioPlayer');
  if(wrap) wrap.style.display = 'none';
  if(iframe) iframe.src = '';
  if(audio){ audio.pause(); audio.src=''; }
  // Stop Jamendo audio
  if(_currentAudio){ _currentAudio.pause(); _currentAudio.src=''; _currentAudio=null; }
  if(_currentTrackId){
    const btn = document.getElementById('jplay_'+_currentTrackId);
    if(btn) btn.textContent = '▶';
    _currentTrackId = null;
  }
}


