window.shareTrofeoFacebook = function(tid, fish, map, weight, nick) {
  var pageUrl = location.origin + location.pathname + "?t=" + tid;
  var kg = (weight ? (weight/1000).toFixed(3).replace(".", ",") + " kg" : "");
  var quote = "🏆 Trofeo de " + (fish||"pez") + (kg ? " — " + kg : "") + " en " + (map||"RF4") + "! 🎣 WikiPediaRF4.UY";
  var fbUrl = "https://www.facebook.com/sharer/sharer.php?u=" + encodeURIComponent(pageUrl) + "&quote=" + encodeURIComponent(quote);
  window.open(fbUrl, "_blank", "width=640,height=460,resizable=yes,scrollbars=yes");
};
