async function checkFriendsBirthdays(){
  if(!window.CU||!db) return;
  try {
    const friends = window.CU.friends || [];
    if(!friends.length) return;

    const now = new Date();
    const todayMMDD = (now.getMonth()+1).toString().padStart(2,'0')+'-'+now.getDate().toString().padStart(2,'0');

    // Evitar notificar dos veces el mismo día
    const lastBdayCheck = localStorage.getItem('_bdayCheck_'+window.CU.id);
    if(lastBdayCheck === todayMMDD) return;

    // Traer datos de los amigos
    const snaps = await Promise.all(friends.slice(0,30).map(fid=>getDoc(doc(db,'users',fid))));
    const cumpleaneros = snaps
      .filter(s=>s.exists())
      .map(s=>({id:s.id,...s.data()}))
      .filter(u=>u.birthdayMMDD===todayMMDD);

    if(!cumpleaneros.length) return;

    // Marcar que ya se chequeó hoy
    localStorage.setItem('_bdayCheck_'+window.CU.id, todayMMDD);

    // Mostrar notificación interna para cada cumpleañero
    for(const u of cumpleaneros){
      const notifs = window.CU.notifs || [];
      const yaNotif = notifs.some(n=>n.bdayUid===u.id && n.bdayDate===todayMMDD);
      if(yaNotif) continue;

      // Agregar notif a nuestro propio perfil
      const newNotif = {
        text:`🎂 ¡Hoy es el cumpleaños de ${u.nick}! Mandále un saludo 🎉`,
        time:Date.now(), read:false,
        bdayUid:u.id, bdayNick:u.nick, bdayDate:todayMMDD
      };
      const mySnap = await getDoc(doc(db,'users',window.CU.id));
      const myNotifs = mySnap.exists() ? (mySnap.data().notifs||[]) : [];
      myNotifs.unshift(newNotif);
      await updateDoc(doc(db,'users',window.CU.id),{notifs:myNotifs.slice(0,40)});
    }

    // Mostrar card especial en el feed si hay cumpleañeros
    showBirthdayCard(cumpleaneros);

  } catch(e){ console.error('checkFriendsBirthdays',e); }
}

function showBirthdayCard(cumpleaneros){
  // Quitar card anterior si existe
  document.getElementById('bdayFeedCard')?.remove();

  const names = cumpleaneros.map(u=>u.nick).join(', ');
  const multi = cumpleaneros.length > 1;

  const card = document.createElement('div');
  card.id = 'bdayFeedCard';
  card.style.cssText = 'background:linear-gradient(135deg,rgba(255,215,0,.12),rgba(255,100,100,.08));border:1px solid rgba(255,215,0,.35);border-radius:14px;padding:18px;margin-bottom:16px;position:relative;overflow:hidden;';

  // Confetti de fondo decorativo
  card.innerHTML = `
    <div style="position:absolute;top:0;left:0;right:0;bottom:0;pointer-events:none;font-size:1.4rem;display:flex;flex-wrap:wrap;gap:8px;padding:8px;opacity:.12;">
      ${'🎂🎉🎈🎁'.repeat(8)}
    </div>
    <div style="position:relative;z-index:1;">
      <div style="font-size:2.2rem;margin-bottom:6px;">🎂</div>
      <div style="font-weight:800;font-size:.95rem;color:gold;margin-bottom:4px;">
        ¡${multi?'Tus amigos cumplen':'Un amigo cumple'} años hoy!
      </div>
      <div style="font-size:.85rem;color:var(--text);margin-bottom:12px;">
        🎉 <strong>${names}</strong> ${multi?'están de cumpleaños':'está de cumpleaños'}
      </div>
      <div style="display:flex;gap:8px;flex-wrap:wrap;">
        ${cumpleaneros.map(u=>`
          <button onclick="bdaySendWish('${u.id}','${(u.nick||'').replace(/'/g,"&apos;")}')"
            style="background:linear-gradient(135deg,#b8860b,#ffd700);border:none;border-radius:100px;padding:7px 16px;font-size:.8rem;font-weight:800;cursor:pointer;color:#000;font-family:'Exo 2',sans-serif;display:flex;align-items:center;gap:5px;transition:transform .15s;"
            onmouseover="this.style.transform='scale(1.05)'" onmouseout="this.style.transform='scale(1)'">
            🎉 Felicitar a ${u.nick}
          </button>`).join('')}
        <button onclick="document.getElementById('bdayFeedCard').remove()"
          style="background:var(--bg3);border:1px solid var(--border);border-radius:100px;padding:7px 14px;font-size:.78rem;font-weight:700;cursor:pointer;color:var(--muted);font-family:'Exo 2',sans-serif;">
          ✕ Cerrar
        </button>
      </div>
    </div>`;

  // Insertar al inicio del feed
  const feed = document.getElementById('feedPosts');
  if(feed) feed.insertBefore(card, feed.firstChild);

  // También insertar en el feed del home si existe
  const homeFeed = document.querySelector('#page-home .feed-col');
  if(homeFeed && !homeFeed.contains(card)) homeFeed.insertBefore(card.cloneNode(true), homeFeed.firstChild);
}

async function bdaySendWish(uid, nick){
  if(!window.CU){ toast('Iniciá sesión primero','err'); return; }
  // Abrir chat con esa persona
  if(typeof openChatWith==='function'){
    cm('mEditProfile'); // cerrar cualquier modal abierto
    om('mMessenger');
    openChatWith(uid, nick);
    // Pre-llenar el mensaje
    setTimeout(()=>{
      const inp = document.getElementById('chatInput');
      if(inp){ inp.value='🎂 ¡Feliz cumpleaños '+nick+'! 🎉🎈'; inp.focus(); }
    }, 400);
  }
  // También notificar al cumpleañero que alguien lo felicitó
  await sendNotifToUser(uid, `🎂 ¡${window.CU.nick} te deseó un feliz cumpleaños! 🎉`);
  toast('¡Mensaje de cumpleaños listo para enviar! 🎉','ok');
}


function filterChatSearch(val){
  const items = document.querySelectorAll('#chatListItems [data-chatuid]');
  const q = val.toLowerCase().trim();
  items.forEach(el=>{
    el.style.display = (!q || (el.dataset.searchname||'').includes(q)) ? '' : 'none';
  });
}

// ── Notif Dropdown (posicionado bajo campana) ──
function openNotifDropdown(){
  const dd = document.getElementById('mNotif');
  if(!dd) return;
  const isMobile = window.innerWidth <= 768;

  // Detectar si ya está visible antes de modificar estilos de posición
  const isCurrentlyOpen = dd.style.display === 'flex';

  if(isMobile){
    dd.style.top = '0';
    dd.style.left = '0';
    dd.style.right = '0';
    dd.style.bottom = '0';
    dd.style.width = '100vw';
    dd.style.maxWidth = '100vw';
    dd.style.height = '100vh';
    dd.style.maxHeight = '100vh';
    dd.style.borderRadius = '0';
  } else {
    const bell = document.getElementById('notifBellBtn');
    if(bell){
      const rect = bell.getBoundingClientRect();
      dd.style.top = (rect.bottom + 6) + 'px';
      const rightSpace = window.innerWidth - rect.right;
      dd.style.right = Math.max(6, rightSpace - 6) + 'px';
      dd.style.left = 'auto';
      dd.style.bottom = 'auto';
      dd.style.width = '380px';
      dd.style.maxWidth = 'calc(100vw - 12px)';
      dd.style.height = 'auto';
      dd.style.maxHeight = 'calc(100vh - ' + (rect.bottom + 16) + 'px)';
      dd.style.borderRadius = '14px';
    }
    dd.style.zIndex = '9999';
  }

  if(isCurrentlyOpen){
    dd.style.display = 'none';
    if(isMobile) document.body.style.overflow = '';
    document.removeEventListener('click', _notifOutsideClick);
    return;
  }

  dd.style.display = 'flex';
  if(isMobile) document.body.style.overflow = 'hidden';
  // Siempre abrir en tab "Todas" para que las notifs sean visibles
  _notifTab = 'all';
  const tabAll = document.getElementById('ntab-all');
  const tabUnread = document.getElementById('ntab-unread');
  if(tabAll){ tabAll.style.background='var(--accent)'; tabAll.style.color='#000'; tabAll.style.fontWeight='700'; }
  if(tabUnread){ tabUnread.style.background='transparent'; tabUnread.style.color='var(--muted)'; tabUnread.style.fontWeight='600'; }
  renderNotifs();

  // Marcar leídas solo después de 2s para que el usuario las vea
  if(_notifs.some(n=>!n.read)){
    setTimeout(async ()=>{
      _notifs.forEach(n=>n.read=true);
      if(window.CU) await updateDoc(doc(db,'users',window.CU.id),{notifs:_notifs}).catch(()=>{});
      renderNotifs(); updateNotifBadge();
    }, 2000);
  }

  // Cerrar al click fuera (solo desktop)
  if(!isMobile){
    setTimeout(()=>{ document.addEventListener('click', _notifOutsideClick); }, 10);
  }
}
function _notifOutsideClick(e){
  const dd = document.getElementById('mNotif');
  const bell = document.getElementById('notifBellBtn');
  if(dd && !dd.contains(e.target) && bell && !bell.contains(e.target)){
    dd.style.display = 'none';
    document.removeEventListener('click', _notifOutsideClick);
  }
}
function closeNotifDropdown(){
  const dd = document.getElementById('mNotif');
  if(dd) dd.style.display = 'none';
  document.body.style.overflow = '';
  document.removeEventListener('click', _notifOutsideClick);
  // no pushState
}
function toggleNotifDropdown(e){
  e.stopPropagation();
  openNotifDropdown();
}

// ── Menú contextual del chat (ruedita) ──
let _chatMenuOpen = null;

function openChatMenu(e, uid, nick, hasUnread, isArchived){
  e.stopPropagation();
  // Cerrar menú anterior si existe
  document.getElementById('chatContextMenu')?.remove();
  document.removeEventListener('click', _closeChatMenu);

  const btn = e.currentTarget;
  const rect = btn.getBoundingClientRect();

  const menu = document.createElement('div');
  menu.id = 'chatContextMenu';
  menu.style.cssText = `position:fixed;z-index:9999;background:var(--bg2);border:1px solid var(--border);border-radius:12px;box-shadow:0 8px 24px rgba(0,0,0,.5);min-width:180px;overflow:hidden;animation:mIn .15s ease;`;
  menu.style.top  = (rect.bottom + 6) + 'px';
  menu.style.right = (window.innerWidth - rect.right) + 'px';

  const safeNick = nick.replace(/'/g,'&apos;');
  const items = [
    !isArchived
      ? { icon:'📦', label:'Archivar chat',    fn:`archiveChat('${uid}','${safeNick}')` }
      : { icon:'📤', label:'Desarchivar chat', fn:`unarchiveChat('${uid}')` },
    hasUnread
      ? { icon:'✓',  label:'Marcar como leído',    fn:`markChatRead('${uid}')` }
      : { icon:'●',  label:'Marcar como no leído',  fn:`markChatUnread('${uid}','${safeNick}')` },
    { icon:'🗑', label:'Eliminar chat', fn:`deleteChatConfirm('${uid}','${safeNick}')`, danger:true },
  ];

  items.forEach(item=>{
    const btn = document.createElement('button');
    btn.style.cssText = `display:flex;align-items:center;gap:10px;width:100%;background:none;border:none;padding:11px 16px;font-size:.84rem;cursor:pointer;font-family:'Exo 2',sans-serif;color:${item.danger?'var(--red)':'var(--text)'};text-align:left;transition:background .12s;`;
    btn.innerHTML = `<span style="font-size:1rem;">${item.icon}</span>${item.label}`;
    btn.onmouseover = ()=>btn.style.background='var(--bg3)';
    btn.onmouseout  = ()=>btn.style.background='none';
    btn.onclick = (ev)=>{ ev.stopPropagation(); document.getElementById('chatContextMenu')?.remove(); new Function(item.fn)(); };
    menu.appendChild(btn);
  });

  document.body.appendChild(menu);
  setTimeout(()=>document.addEventListener('click', _closeChatMenu), 10);
}

function _closeChatMenu(e){
  const m = document.getElementById('chatContextMenu');
  if(m && !m.contains(e.target)){ m.remove(); document.removeEventListener('click', _closeChatMenu); }
}

async function archiveChat(uid, nick){
  if(!window.CU) return;
  const arch = window.CU.archivedChats || [];
  if(!arch.includes(uid)){
    arch.push(uid);
    window.CU.archivedChats = arch;
    await updateDoc(doc(db,'users',window.CU.id),{archivedChats:arch});
  }
  toast(`💬 Chat con ${nick} archivado 📦`,'ok');
  // Cambiar al tab archivados para que el usuario lo vea inmediatamente
  _currentChatTab = 'archived';
  ['all','unread','archived'].forEach(t=>{
    const btn = document.getElementById('chatTab-'+t);
    if(!btn) return;
    const active = t==='archived';
    btn.style.borderBottom = active ? '2px solid var(--accent)' : '2px solid transparent';
    btn.style.color = active ? 'var(--accent)' : 'var(--muted)';
    btn.style.fontWeight = active ? '700' : '600';
  });
  const _archList = document.getElementById('messengerList');
  if(_archList && _archList.style.display !== 'none') _archList.innerHTML = _buildMessengerHTML();
}

async function unarchiveChat(uid){
  if(!window.CU) return;
  window.CU.archivedChats = (window.CU.archivedChats||[]).filter(id=>id!==uid);
  await updateDoc(doc(db,'users',window.CU.id),{archivedChats:window.CU.archivedChats});
  toast('Chat desarchivado','ok');
  // Volver al tab "Todos" después de desarchivar
  _currentChatTab = 'all';
  ['all','unread','archived'].forEach(t=>{
    const btn = document.getElementById('chatTab-'+t);
    if(!btn) return;
    const active = t==='all';
    btn.style.borderBottom = active ? '2px solid var(--accent)' : '2px solid transparent';
    btn.style.color = active ? 'var(--accent)' : 'var(--muted)';
    btn.style.fontWeight = active ? '700' : '600';
  });
  const _uarchList = document.getElementById('messengerList');
  if(_uarchList && _uarchList.style.display !== 'none') _uarchList.innerHTML = _buildMessengerHTML();
}

async function markChatRead(uid){
  if(!window.CU) return;
  try{
    const chatId = [window.CU.id, uid].sort().join('_');
    const q = query(collection(db,'chats',chatId,'messages'), orderBy('time','desc'), limit(50));
    const snap = await getDocs(q);
    const myId = window.CU.id;
    const toMark = snap.docs.filter(d=>d.data().uid!==myId && !d.data().read);
    await Promise.all(toMark.map(d=>updateDoc(d.ref,{read:true})));
    if(_chatLastMsgs[uid]) _chatLastMsgs[uid].unread = false;
    updateMsgBadge();
    renderMessengerList();
    toast('Chat marcado como leído ✓','ok');
  }catch(e){ console.error(e); }
}

async function markChatUnread(uid, nick){
  if(_chatLastMsgs[uid]) _chatLastMsgs[uid].unread = true;
  renderMessengerList();
  toast(`Chat con ${nick} marcado como no leído ●`,'ok');
}

async function deleteChatConfirm(uid, nick){
  if(!confirm(`¿Eliminar el chat con ${nick}? Esto borra el historial solo de tu lado.`)) return;
  try{
    const chatId = [window.CU.id, uid].sort().join('_');
    const q = query(collection(db,'chats',chatId,'messages'), orderBy('time','desc'));
    const snap = await getDocs(q);
    // Marcar TODOS (propios y recibidos) como borrados para mí + marcar leídos
    await Promise.all(snap.docs.map(d=>{
      const df = d.data().deletedFor || {};
      df[window.CU.id] = true;
      return updateDoc(d.ref, {deletedFor: df, read: true});
    }));
    // Guardar en Firestore el ID del amigo como chat borrado
    const deleted = window.CU.deletedChats || [];
    if(!deleted.includes(uid)) deleted.push(uid);
    window.CU.deletedChats = deleted;
    await updateDoc(doc(db,'users',window.CU.id), {deletedChats: deleted});
    // Limpiar estado local
    delete _chatLastMsgs[uid];
    // Limpiar notifs de mensajes de este usuario en _notifs
    const prevLen = _notifs.length;
    _notifs = _notifs.filter(n=>!(n.fromId===uid || (n.text&&n.text.startsWith('💬')&&n.text.includes(nick))));
    if(_notifs.length !== prevLen){
      await updateDoc(doc(db,'users',window.CU.id),{notifs:_notifs}).catch(()=>{});
    }
    updateNotifBadge(); updateMsgBadge();
    renderMessengerList();
    toast('✓ Chat eliminado','ok');
  }catch(e){ console.error(e); toast('Error al eliminar','err'); }
}


Object.entries(_expose).forEach(([k,v])=>{ window[k]=v; });
// Replay any calls that happened before module loaded
if(window._q) window._q.forEach(([name,args])=>{ if(window[name]) window[name](...args); });

