// ============================================================
// ===== BUEN PESCADOR (likes en tiempo real) ==================
// ============================================================
async function togglePescaLike(targetUid){
  if(!window.CU){ toast('Iniciá sesión primero','err'); return; }
  if(window.CU.id === targetUid){ toast('No podés darte "Buen pescador" a vos mismo 😄','err'); return; }
  try {
    const ref = doc(db,'users',targetUid);
    const snap = await getDoc(ref);
    if(!snap.exists()) return;
    const likes = snap.data().pescaLikes || {};
    const myId = window.CU.id;
    if(likes[myId]){
      delete likes[myId];
      await updateDoc(ref, {pescaLikes: likes});
      toast('Retiraste tu "Buen pescador" 🎣','inf');
    } else {
      likes[myId] = true;
      await updateDoc(ref, {pescaLikes: likes});
      toast('¡Le diste "Buen pescador" 🎣!','ok');
      // Notificación al dueño del perfil
      try {
        const notifs = snap.data().notifs || [];
        notifs.unshift({ type:'pescador', fromId:myId, fromNick:window.CU.nick, text:`🎣 ${window.CU.nick} te dio "Buen pescador"`, time:Date.now() });
        await updateDoc(ref, { notifs: notifs.slice(0,50) });
      } catch(e){}
    }
  } catch(e){ console.error(e); toast('Error','err'); }
}
window.togglePescaLike = togglePescaLike;

// ── SEGUIR / DEJAR DE SEGUIR ──
async function toggleFollow(targetUid, targetNick, btn){
  const myId = window.CU?.id;
  if(!myId){ toast('Iniciá sesión para seguir','err'); return; }
  if(!targetUid) return;
  try{
    const targetRef = doc(db,'users',targetUid);
    const myRef = doc(db,'users',myId);
    const snap = await getDoc(targetRef);
    if(!snap.exists()) return;
    const followers = snap.data().followers || [];
    const isFollowing = followers.includes(myId);
    if(isFollowing){
      // Dejar de seguir
      await updateDoc(targetRef, { followers: arrayRemove(myId) });
      await updateDoc(myRef, { following: arrayRemove(targetUid) });
      if(window.CU) window.CU.following = (window.CU.following||[]).filter(x=>x!==targetUid);
      toast('Dejaste de seguir a '+targetNick,'ok');
    } else {
      // Seguir
      await updateDoc(targetRef, { followers: arrayUnion(myId) });
      await updateDoc(myRef, { following: arrayUnion(targetUid) });
      if(window.CU){ if(!window.CU.following) window.CU.following=[]; window.CU.following.push(targetUid); }
      toast('Ahora seguís a '+targetNick+' ⭐','suc');
      // Notificación al seguido
      try{
        await addDoc(collection(db,'notifications'),{
          toUid: targetUid, fromId: myId, fromNick: window.CU.nick||'',
          type:'follow', text:(window.CU.nick||'alguien')+' comenzó a seguirte ⭐',
          time: serverTimestamp(), read:false
        });
      }catch(e){}
    }
  }catch(e){ console.error(e); toast('Error al actualizar seguidores','err'); }
}
window.toggleFollow = toggleFollow;

// ── ELIMINAR AMIGO ──
async function removeFriend(targetUid, targetNick){
  if(!window.CU?.id) return;
  const myId = window.CU.id;
  // Confirmación simple
  const confirmed = await new Promise(res => {
    const m = document.createElement('div');
    m.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.75);display:flex;align-items:center;justify-content:center;';
    m.innerHTML = `<div style="background:var(--bg2);border:1px solid var(--border);border-radius:16px;padding:28px 24px;width:320px;max-width:92vw;text-align:center;">
      <div style="font-size:1.5rem;margin-bottom:10px;">👥</div>
      <div style="font-size:1rem;font-weight:800;margin-bottom:8px;">¿Eliminar a ${targetNick}?</div>
      <div style="font-size:.82rem;color:var(--muted);margin-bottom:20px;">Ya no serán amigos y no podrán enviarse mensajes.</div>
      <div style="display:flex;gap:10px;justify-content:center;">
        <button id="_rmvCancel" style="padding:9px 22px;background:var(--bg3);border:1px solid var(--border);color:var(--text);border-radius:8px;font-size:.88rem;font-weight:700;cursor:pointer;font-family:'Exo 2',sans-serif;">Cancelar</button>
        <button id="_rmvConfirm" style="padding:9px 22px;background:var(--red);border:none;color:#fff;border-radius:8px;font-size:.88rem;font-weight:700;cursor:pointer;font-family:'Exo 2',sans-serif;">Eliminar</button>
      </div>
    </div>`;
    document.body.appendChild(m);
    m.querySelector('#_rmvCancel').onclick = () => { m.remove(); res(false); };
    m.querySelector('#_rmvConfirm').onclick = () => { m.remove(); res(true); };
    m.addEventListener('click', e => { if(e.target===m){ m.remove(); res(false); } });
  });
  if(!confirmed) return;
  try {
    const myRef = doc(db,'users',myId);
    const theirRef = doc(db,'users',targetUid);
    await updateDoc(myRef, { friends: arrayRemove(targetUid) });
    await updateDoc(theirRef, { friends: arrayRemove(myId) });
    // Actualizar cache local
    if(window.CU.friends) window.CU.friends = window.CU.friends.filter(id=>id!==targetUid);
    if(window.CU.friendsList) window.CU.friendsList = window.CU.friendsList.filter(f=>f.id!==targetUid);
    toast(`${targetNick} eliminado de tus amigos`,'ok');
    // Refrescar UI
    const card = document.querySelector(`[data-fid="${targetUid}"]`);
    if(card){ card.style.opacity='0'; card.style.transform='scale(.92)'; card.style.transition='all .2s'; setTimeout(()=>card.remove(),200); }
    // Actualizar contador
    const fc = document.getElementById('profFriendCount');
    if(fc) fc.textContent = (window.CU.friends||[]).length;
    // Refrescar sidebar
    setTimeout(()=>{ renderSidebarFriends?.(); renderProfileFriendsList?.(); }, 300);
  } catch(e){ console.error(e); toast('Error al eliminar amigo','err'); }
}
window.removeFriend = removeFriend;


// ── LISTA DE SEGUIDORES ──
async function openFollowersList(uid){
  if(!uid) return;
  const m = document.createElement('div');
  m.id = '_followersModal';
  m.style.cssText='position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.75);display:flex;align-items:center;justify-content:center;';
  m.innerHTML=`<div style="background:var(--bg2);border:1px solid var(--border);border-radius:16px;padding:0;width:360px;max-width:95vw;max-height:80vh;overflow:hidden;display:flex;flex-direction:column;">
    <div style="display:flex;justify-content:space-between;align-items:center;padding:16px 20px;border-bottom:1px solid var(--border);">
      <span style="font-size:1rem;font-weight:800;">⭐ Seguidores</span>
      <button onclick="document.getElementById('_followersModal').remove()" style="background:rgba(255,255,255,.1);border:none;color:var(--text);width:30px;height:30px;border-radius:50%;cursor:pointer;">✕</button>
    </div>
    <div id="_followersList" style="overflow-y:auto;padding:12px 16px;flex:1;">
      <div style="text-align:center;padding:20px;color:var(--muted);">⏳ Cargando...</div>
    </div>
  </div>`;
  m.addEventListener('click',e=>{ if(e.target===m) m.remove(); });
  document.body.appendChild(m);
  try{
    const snap = await getDoc(doc(db,'users',uid));
    if(!snap.exists()){ document.getElementById('_followersList').innerHTML='<div style="text-align:center;padding:20px;color:var(--muted);">Sin datos</div>'; return; }
    const followers = snap.data().followers || [];
    if(!followers.length){ document.getElementById('_followersList').innerHTML='<div style="text-align:center;padding:20px;color:var(--muted);">Nadie sigue este perfil aún.</div>'; return; }
    const snaps = await Promise.all(followers.map(fid=>getDoc(doc(db,'users',fid))));
    const listEl = document.getElementById('_followersList');
    if(!listEl) return;
    listEl.innerHTML = snaps.filter(s=>s.exists()).map(s=>{
      const fd = s.data(); const fid = s.id;
      const av = fd.av ? `<img src="${fd.av}" style="width:100%;height:100%;object-fit:cover;border-radius:50%;">` : `<span style="font-size:.9rem;font-weight:700;color:var(--accent);">${(fd.nick||'?')[0].toUpperCase()}</span>`;
      return `<div onclick="document.getElementById('_followersModal').remove();openUserProfile('${fid}','${(fd.nick||'').replace(/'/g,"\'")}');" style="display:flex;align-items:center;gap:12px;padding:10px 4px;border-bottom:1px solid var(--border);cursor:pointer;border-radius:8px;transition:background .15s;" onmouseover="this.style.background='rgba(255,255,255,.04)'" onmouseout="this.style.background=''">
        <div style="width:40px;height:40px;border-radius:50%;overflow:hidden;background:var(--bg3);border:2px solid var(--border);flex-shrink:0;display:flex;align-items:center;justify-content:center;">${av}</div>
        <div><div style="font-size:.88rem;font-weight:700;">${fd.nick||'?'}</div><div style="font-size:.72rem;color:var(--muted);">${fd.country||''}</div></div>
      </div>`;
    }).join('');
  }catch(e){ const le=document.getElementById('_followersList'); if(le) le.innerHTML='<div style="text-align:center;padding:20px;color:var(--muted);">Error al cargar</div>'; }
}

