const WK_ADMIN = 'ruizgustavo12';
let _wkImgs = [], _wkEditId = null, _wkRkMode = 'score', _wkLoaded = false;
let _wkAllTrophies = []; // cache local

// Sub-page navigation
window.wkGp = (subId, btn) => {
  document.querySelectorAll('#page-wiki-trofeos > [id^="wk-"]').forEach(p => p.style.display='none');
  const el = document.getElementById(subId);
  if(el) el.style.display = 'block';
  document.querySelectorAll('.wk-nb').forEach(b=>b.classList.remove('on'));
  if(btn) btn.classList.add('on');
  // Load data for each sub-page
  if(subId==='wk-trophies') wkRenderTrophies();
  if(subId==='wk-ranking') wkRenderRanking();
  if(subId==='wk-records') wkRenderRecords();
  if(subId==='wk-sheet') wkRenderSheet();
  if(subId==='wk-admin') wkRenderAdmin();
  if(subId==='wk-inicio') wkLoadHome();
};

// Init - called once when entering page-wiki-trofeos
window.wkInit = () => {
  if(_wkLoaded) return; _wkLoaded = true;
  wkLoadHome();
  wkUpdateBannerCounts();
  // Show/hide auth-dependent buttons
  const cu = window.CU;
  if(cu) {
    const pubBtn = document.getElementById('wkNbPublish');
    if(pubBtn) pubBtn.style.display = '';
    const admBtn = document.getElementById('wkNbAdmin');
    if(admBtn && (cu.nick===WK_ADMIN||cu.role==='admin')) admBtn.style.display = '';
  }
};

// Update banner counters
async function wkUpdateBannerCounts() {
  try {
    // Leer config/stats en vez de toda la coleccion (1 lectura en vez de N)
    const statsSnap = await getDoc(doc(db,'config','stats'));
    const total = statsSnap.exists() ? (statsSnap.data().totalTrophies||0) : 0;
    const el = document.getElementById('wkTotalTrophy');
    if(el) el.textContent = total||'—';
    // Online count from presence (charlasrf4)
    const presSnap = await getDocs(query(collection(db,'presence'), limit(200)));
    const online = presSnap.docs.filter(d => {
      const t = d.data().lastSeen?.toMillis?.() || 0;
      return Date.now() - t < 5*60*1000;
    }).length;
    const onEl = document.getElementById('wkOnlineCount');
    if(onEl) onEl.textContent = online||'—';
  } catch(e){}
}

// Card HTML builder
function wkCard(t, showSt=false) {
  const liked = window.CU && t.reactions && t.reactions[window.CU.id]?.emoji==='❤️';
  return `<div class="tcard" onclick="wkOpenDet('${t.id}')">
    <div class="tcard-img">
      ${t.images&&t.images[0]?`<img src="${t.images[0]}" alt="${wkEsc(t.fish)}" loading="lazy">`:`<span>🐟</span>`}
      <div class="twbadge">${fmtKg(t.weight||0)}</div>
      ${showSt&&t.status?`<div class="status-badge status-${t.status}">${t.status==='pending'?'⏳ Pendiente':t.status==='approved'?'✅ Aprobado':'❌ Rechazado'}</div>`:''}
    </div>
    <div class="tcbody">
      <div class="tcfish">${wkEsc(t.fish)}</div>
      <div class="tctags">
        <span class="tag">${wkEsc(t.map)}</span>
        <span class="tag g">${wkEsc(t.technique)}</span>
        ${t.spot?`<span class="tag y">📍 ${wkEsc(t.spot)}</span>`:''}
      </div>
      <div class="tcauthor">
        <div class="av" style="width:28px;height:28px;font-size:10px;flex-shrink:0;border:1.5px solid rgba(0,198,255,.25);">${t.userPhoto?`<img src="${t.userPhoto}" alt="" style="width:100%;height:100%;object-fit:cover;border-radius:50%;">`:(t.userNick||'?')[0].toUpperCase()}</div>
        <div style="min-width:0;flex:1;">
          <div class="tcauthor-label">Pescador</div>
          <div class="tcauthor-nick">${wkEsc(t.userNick||'Anónimo')}</div>
        </div>
        <span style="font-size:.9rem;opacity:.4;flex-shrink:0;">🎣</span>
      </div>
    </div>
    <div class="tcfoot">
      <div class="rxns">
        <button class="rxb ${liked?'lk':''}" onclick="event.stopPropagation();wkTogLike('${t.id}')">❤ ${t.likes||0}</button>
        <button class="rxb" onclick="event.stopPropagation();wkOpenDet('${t.id}')">💬 ${t.commentCount||0}</button>
      </div>
      <div style="display:flex;align-items:center;gap:6px;">
        <div class="vct">👁 ${t.views||0}</div>
        <button onclick="event.stopPropagation();shareTrofeoFacebook('${t.id}','${wkEsc(t.fish)}','${wkEsc(t.map)}',${t.weight||0},'${wkEsc(t.userNick||'')}','${wkEsc(t.images&&t.images[0]?t.images[0]:'')}');"
          title="Compartir en Facebook"
          style="display:flex;align-items:center;gap:4px;background:#1877F2;border:none;border-radius:20px;padding:4px 10px;cursor:pointer;font-family:'Exo 2',sans-serif;font-size:.68rem;font-weight:700;color:#fff;transition:background .15s;"
          onmouseover="this.style.background='#166fe5'" onmouseout="this.style.background='#1877F2'">
          <svg viewBox="0 0 24 24" width="13" height="13" fill="#fff" style="flex-shrink:0"><path d="M24 12.073C24 5.405 18.627 0 12 0S0 5.405 0 12.073C0 18.1 4.388 23.094 10.125 24v-8.437H7.078v-3.49h3.047V9.41c0-3.025 1.792-4.697 4.533-4.697 1.312 0 2.686.236 2.686.236v2.97h-1.513c-1.491 0-1.956.93-1.956 1.886v2.268h3.328l-.532 3.49h-2.796V24C19.612 23.094 24 18.1 24 12.073z"/></svg>
          Compartir
        </button>
      </div>
    </div>
  </div>`;
}

function wkEsc(s){ return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

// Load home - recent trophies
async function wkLoadHome() {
  const grid = document.getElementById('wkHomeGrid');
  const empty = document.getElementById('wkHomeEmpty');
  if(!grid) return;
  grid.innerHTML = '<div class="wk-ld"><div class="wk-sp"></div></div>';
  try {
    const snap = await getDocs(query(collection(db,'trofeosPendientes'), where('status','==','approved'), limit(50)));
    _wkAllTrophies = snap.docs.map(d=>({id:d.id,...d.data()}));
    if(_wkAllTrophies.length===0){ grid.innerHTML=''; empty.style.display='block'; return; }
    empty.style.display='none';
    grid.innerHTML = _wkAllTrophies.map(t=>wkCard(t)).join('');
    // Update stats
    const hst = document.getElementById('wkTotalTrophy');
    if(hst) hst.textContent = _wkAllTrophies.length+'+';
  } catch(e) {
    // fallback: try without orderBy
    try {
      const snap2 = await getDocs(query(collection(db,'trofeosPendientes'), where('status','==','approved'), limit(12)));
      _wkAllTrophies = snap2.docs.map(d=>({id:d.id,...d.data()}));
      if(!_wkAllTrophies.length){ grid.innerHTML=''; empty.style.display='block'; return; }
      empty.style.display='none';
      grid.innerHTML = _wkAllTrophies.map(t=>wkCard(t)).join('');
    } catch(e2){ grid.innerHTML='<div class="wk-empty"><div class="wk-ei">⚠️</div><div class="wk-et">Error al cargar</div></div>'; }
  }
}

// Home map filter
window.wkOnHomeMapChange = async () => {
  const map = document.getElementById('wkHomeMapSelect').value;
  const res = document.getElementById('wkHomeMapResults');
  const grid = document.getElementById('wkHomeMapGrid');
  const title = document.getElementById('wkHomeMapTitle');
  const count = document.getElementById('wkHomeMapCount');
  const empty = document.getElementById('wkHomeMapEmpty');
  if(!map){ if(res) res.style.display='none'; return; }
  res.style.display='block';
  title.textContent = '🗺️ '+map;
  grid.innerHTML = '<div class="wk-ld"><div class="wk-sp"></div></div>';
  empty.style.display='none';
  try {
    const snap = await getDocs(query(collection(db,'trofeosPendientes'), where('status','==','approved'), where('map','==',map), limit(100)));
    const items = snap.docs.map(d=>({id:d.id,...d.data()}));
    count.textContent = items.length + ' trofeos';
    if(!items.length){ grid.innerHTML=''; empty.style.display='block'; return; }
    grid.innerHTML = items.map(t=>wkCard(t)).join('');
  } catch(e){ grid.innerHTML=''; empty.style.display='block'; }
};

// Gallery: render all trophies with filters
window.wkRenderTrophies = async () => {
  const grid = document.getElementById('wkTGrid');
  const empty = document.getElementById('wkTEmpty');
  if(!grid) return;
  grid.innerHTML = '<div class="wk-ld"><div class="wk-sp"></div></div>';
  try {
    const snap = await getDocs(query(collection(db,'trofeosPendientes'), where('status','==','approved'), limit(100)));
    let items = snap.docs.map(d=>({id:d.id,...d.data()}));
    // Apply filters
    const fMap = document.getElementById('wkFMap')?.value||'';
    const fTech = document.getElementById('wkFTech')?.value||'';
    const fSearch = (document.getElementById('wkFSearch')?.value||'').toLowerCase().trim();
    if(fMap) items = items.filter(t=>t.map===fMap);
    if(fTech) items = items.filter(t=>t.technique===fTech);
    if(fSearch) items = items.filter(t=>(t.fish||'').toLowerCase().includes(fSearch)||(t.description||'').toLowerCase().includes(fSearch));
    if(!items.length){ grid.innerHTML=''; empty.style.display='block'; return; }
    empty.style.display='none';
    grid.innerHTML = items.map(t=>wkCard(t)).join('');
    // Show publish button if logged in
    const btn = document.getElementById('wkPubBtn');
    if(btn && window.CU) btn.style.display='';
  } catch(e){
    // fallback without orderBy
    try {
      const snap2 = await getDocs(query(collection(db,'trofeosPendientes'), where('status','==','approved'), limit(100)));
      let items2 = snap2.docs.map(d=>({id:d.id,...d.data()}));
      const fMap = document.getElementById('wkFMap')?.value||'';
      const fTech = document.getElementById('wkFTech')?.value||'';
      const fSearch = (document.getElementById('wkFSearch')?.value||'').toLowerCase().trim();
      if(fMap) items2 = items2.filter(t=>t.map===fMap);
      if(fTech) items2 = items2.filter(t=>t.technique===fTech);
      if(fSearch) items2 = items2.filter(t=>(t.fish||'').toLowerCase().includes(fSearch));
      if(!items2.length){ grid.innerHTML=''; empty.style.display='block'; return; }
      empty.style.display='none';
      grid.innerHTML = items2.map(t=>wkCard(t)).join('');
    } catch(e2){ grid.innerHTML='<div class="wk-empty"><div class="wk-ei">⚠️</div><div class="wk-et">Error al cargar trofeos</div></div>'; }
  }
};

// Ranking
window.wkSwR = (el, m) => {
  _wkRkMode = m;
  document.querySelectorAll('#wk-ranking .vb').forEach(v=>v.classList.remove('on'));
  el.classList.add('on');
  wkRenderRanking();
};

window.wkRenderRanking = async () => {
  const podium = document.getElementById('wkRankPodium');
  const list = document.getElementById('wkRankList');
  const loader = document.getElementById('wkRankLoad');
  if(!podium) return;
  if(loader) loader.style.display='flex';
  podium.innerHTML=''; list.innerHTML='';
  try {
    const tS = await getDocs(query(collection(db,'trofeosPendientes'), where('status','==','approved'), limit(200)));
    const trs = tS.docs.map(d=>({id:d.id,...d.data()}));
    // Build user stats from trophies
    const byUser = {};
    trs.forEach(t=>{
      if(!t.userId) return;
      if(!byUser[t.userId]) byUser[t.userId]={userId:t.userId,nick:t.userNick||'?',photo:t.userPhoto||'',role:t.userRole||'novato',tc:0,tl:0,cm:0};
      byUser[t.userId].tc++;
      byUser[t.userId].tl += (t.likes||0);
      byUser[t.userId].cm += (t.commentCount||0);
    });
    const users = Object.values(byUser).map(u=>({...u, score:(u.tc*3)+(u.tl*2)+(u.cm*1)}));
    const sortFn = {posts:(a,b)=>b.tc-a.tc, likes:(a,b)=>b.tl-a.tl, comments:(a,b)=>b.cm-a.cm, score:(a,b)=>b.score-a.score};
    const sorted = [...users].sort(sortFn[_wkRkMode]||sortFn.score);
    if(loader) loader.style.display='none';
    if(!sorted.length){ podium.innerHTML='<div class="wk-empty"><div class="wk-ei">🎣</div><div class="wk-et">Sin datos de ranking aún</div></div>'; return; }
    const medals=['🥇','🥈','🥉'], colors=['#ffd700','#c0c8d4','#cd7f32'];
    const top3 = sorted.slice(0,3);
    const order=[1,0,2]; // 2nd, 1st, 3rd for podium layout
    podium.innerHTML = order.filter(i=>top3[i]).map(i=>{
      const u=top3[i], pos=i+1;
      const val = _wkRkMode==='posts'?u.tc+' posts':_wkRkMode==='likes'?u.tl+' likes':_wkRkMode==='comments'?u.cm+' cmts':u.score+' pts';
      return `<div class="rk-podium-slot p${pos}" style="order:${pos===1?2:pos===2?1:3}">
        <div class="rk-podium-medal" style="font-size:${pos===1?'2.2':'1.8'}rem">${medals[i]}</div>
        <div class="av" style="width:${pos===1?56:46}px;height:${pos===1?56:46}px;font-size:${pos===1?1.4:.9}rem">${u.photo?`<img src="${u.photo}" alt="">`:(u.nick||'?')[0].toUpperCase()}</div>
        <div class="rk-podium-nick" style="font-size:${pos===1?'.82':'.72'}rem;max-width:${pos===1?130:100}px">${wkEsc(u.nick)}</div>
        <div class="rk-podium-val" style="background:${colors[i]}">${val}</div>
        <div class="rk-podium-step" style="height:${pos===1?60:pos===2?40:24}px;background:linear-gradient(180deg,${colors[i]}22,${colors[i]}08)"></div>
      </div>`;
    }).join('');
    list.innerHTML = sorted.slice(3).map((u,i)=>{
      const pos=i+4;
      const val = _wkRkMode==='posts'?u.tc:_wkRkMode==='likes'?u.tl:_wkRkMode==='comments'?u.cm:u.score;
      const unit = _wkRkMode==='posts'?'posts':_wkRkMode==='likes'?'likes':_wkRkMode==='comments'?'cmts':'pts';
      return `<div class="rk-item">
        <div class="rk-pos">${pos}</div>
        <div class="av" style="width:36px;height:36px;font-size:.9rem">${u.photo?`<img src="${u.photo}" alt="">`:(u.nick||'?')[0].toUpperCase()}</div>
        <div class="rk-info">
          <div class="rk-nick">${wkEsc(u.nick)}</div>
          <div class="rk-meta"><span>🏆 ${u.tc} trofeos</span><span>❤️ ${u.tl} likes</span></div>
        </div>
        <div class="rk-score">${val}<span class="rk-score-unit">${unit}</span></div>
      </div>`;
    }).join('');
  } catch(e){
    if(loader) loader.style.display='none';
    podium.innerHTML='<div class="wk-empty"><div class="wk-ei">⚠️</div><div class="wk-et">Error al cargar ranking</div></div>';
  }
};

// Records
window.wkRenderRecords = async () => {
  const el = document.getElementById('wkRecordsContent');
  if(!el) return;
  el.innerHTML = '<div class="wk-ld"><div class="wk-sp"></div></div>';
  try {
    const snap = await getDocs(query(collection(db,'trofeosPendientes'), where('status','==','approved'), limit(200)));
    const trs = snap.docs.map(d=>({id:d.id,...d.data()}));
    // Group by fish species, find heaviest
    const byFish = {};
    trs.forEach(t=>{
      const fish = (t.fish||'').trim();
      if(!fish) return;
      if(!byFish[fish]||parseFloat(t.weight||0)>parseFloat(byFish[fish].weight||0)) byFish[fish]=t;
    });
    const records = Object.entries(byFish).sort((a,b)=>parseFloat(b[1].weight||0)-parseFloat(a[1].weight||0));
    if(!records.length){ el.innerHTML='<div class="wk-empty"><div class="wk-ei">🐟</div><div class="wk-et">Sin records aún</div></div>'; return; }
    // Build user stats for trophy count
    const byUser = {};
    trs.forEach(t=>{ if(t.userId) byUser[t.userId]=(byUser[t.userId]||0)+1; });
    // Top fishermen by count
    const topFishermen = Object.entries(byUser).sort((a,b)=>b[1]-a[1]).slice(0,10);
    // Find user data
    const userNicks = {};
    trs.forEach(t=>{ if(t.userId&&t.userNick) userNicks[t.userId]=t.userNick; });
    el.innerHTML = `
      <div style="margin-bottom:28px">
        <div style="font-family:'Orbitron',monospace;font-size:.9rem;font-weight:800;color:#ffd700;margin-bottom:12px">🏆 Récord por Especie</div>
        <div style="overflow-x:auto">
          <table class="records-table">
            <thead><tr>
              <th>#</th><th>Especie</th><th>Peso</th><th>Pescador</th><th>Mapa</th><th>Técnica</th>
            </tr></thead>
            <tbody>
              ${records.map(([fish,t],i)=>`<tr onclick="wkOpenDet('${t.id}')">
                <td><span style="font-family:'Orbitron',monospace;font-weight:800;color:${i===0?'#ffd700':i===1?'#c0c8d4':i===2?'#cd7f32':'var(--muted,#567890)'}">${i+1}</span></td>
                <td class="rec-fish">${wkEsc(fish)}</td>
                <td class="rec-weight">${fmtKg(t.weight||0)}</td>
                <td>${wkEsc(t.userNick||'?')}</td>
                <td style="font-size:.8rem;color:var(--muted,#567890)">${wkEsc(t.map||'?')}</td>
                <td style="font-size:.8rem;color:var(--muted,#567890)">${wkEsc(t.technique||'?')}</td>
              </tr>`).join('')}
            </tbody>
          </table>
        </div>
      </div>
      <div>
        <div style="font-family:'Orbitron',monospace;font-size:.9rem;font-weight:800;color:#00d4ff;margin-bottom:12px">🎣 Top Pescadores (por cantidad)</div>
        <div class="rk-list">
          ${topFishermen.map(([uid,count],i)=>`<div class="rk-item">
            <div class="rk-pos" style="color:${i===0?'#ffd700':i===1?'#c0c8d4':i===2?'#cd7f32':'var(--muted)'}">${i+1}</div>
            <div class="rk-info"><div class="rk-nick">${wkEsc(userNicks[uid]||'?')}</div></div>
            <div class="rk-score">${count}<span class="rk-score-unit">trofeos</span></div>
          </div>`).join('')}
        </div>
      </div>`;
  } catch(e){ el.innerHTML='<div class="wk-empty"><div class="wk-ei">⚠️</div><div class="wk-et">Error al cargar records</div></div>'; }
};

// Open trophy detail
let _wkSheetAll = [];

window.wkRenderSheet = async () => {
  const el = document.getElementById('wkSheetContent');
  if(!el) return;
  el.innerHTML = '<div class="wk-ld"><div class="wk-sp"></div></div>';
  try {
    const snap = await getDocs(query(collection(db,'trofeosPendientes'), where('status','==','approved'), limit(200)));
    _wkSheetAll = snap.docs.map(d=>({id:d.id,...d.data()}));
    wkBuildSheetTable(_wkSheetAll);
  } catch(e) {
    el.innerHTML = '<div class="wk-empty"><div class="wk-ei">⚠️</div><div class="wk-et">Error al cargar tabla</div></div>';
  }
};

window.wkFilterSheet = () => {
  const q = (document.getElementById('wkSheetSearch')?.value||'').toLowerCase();
  const filtered = q ? _wkSheetAll.filter(t=>
    (t.fish||'').toLowerCase().includes(q)||
    (t.map||'').toLowerCase().includes(q)||
    (t.technique||'').toLowerCase().includes(q)||
    (t.userNick||'').toLowerCase().includes(q)||
    (t.spot||'').toLowerCase().includes(q)
  ) : _wkSheetAll;
  wkBuildSheetTable(filtered);
};

function wkBuildSheetTable(list) {
  const el = document.getElementById('wkSheetContent');
  if(!el) return;
  const sortVal = document.getElementById('wkSheetSort')?.value||'date';
  const sorted = [...list].sort((a,b)=>{
    if(sortVal==='weight') return parseFloat(b.weight||0)-parseFloat(a.weight||0);
    if(sortVal==='fish') return (a.fish||'').localeCompare(b.fish||'');
    if(sortVal==='likes') return (b.likes||0)-(a.likes||0);
    return (b.createdAt?.seconds||0)-(a.createdAt?.seconds||0);
  });
  if(!sorted.length){
    el.innerHTML='<div class="wk-empty"><div class="wk-ei">🐟</div><div class="wk-et">Sin trofeos aún</div></div>'; return;
  }
  const medals = {0:'🥇',1:'🥈',2:'🥉'};
  el.innerHTML = `<div style="overflow-x:auto">
    <table class="records-table" style="min-width:650px">
      <thead><tr>
        <th style="width:42px">#</th>
        <th>Especie</th>
        <th>⚖ Peso</th>
        <th>🗺 Mapa</th>
        <th>🎣 Técnica</th>
        <th>👤 Pescador</th>
        <th>📅 Fecha</th>
        <th>❤</th>
      </tr></thead>
      <tbody>
        ${sorted.map((t,i)=>{
          const medal = medals[i]||'';
          const dateStr = t.date||(t.createdAt?.toDate?.()?.toLocaleDateString('es-AR')||'');
               return `<tr style="cursor:pointer" onclick="wkOpenDet('${t.id}')">
            <td><span style="font-family:'Orbitron',monospace;font-weight:800;font-size:.8rem;color:${i===0?'#ffd700':i===1?'#c0c8d4':i===2?'#cd7f32':'var(--text-muted,#567)'}">${medal||('#'+(i+1))}</span></td>
            <td class="rec-fish">${wkEsc(t.fish||'?')}</td>
            <td class="rec-weight">${fmtKg(t.weight||0)}</td>
            <td style="font-size:.82rem">${wkEsc(t.map||'?')}</td>
            <td style="font-size:.82rem;color:var(--text-muted,#567)">${wkEsc(t.technique||'?')}</td>
            <td>
              <div style="display:flex;align-items:center;gap:7px">
                <div class="av" style="width:28px;height:28px;font-size:.7rem;flex-shrink:0">${t.userPhoto?`<img src="${t.userPhoto}" alt="">`:((t.userNick||'?')[0].toUpperCase())}</div>
                <span style="font-size:.82rem;font-weight:600">${wkEsc(t.userNick||'?')}</span>
              </div>
            </td>
            <td style="font-size:.78rem;color:var(--text-muted,#567)">${dateStr}</td>
            <td style="color:#ff6688;font-weight:700">${t.likes||0}</td>
          </tr>`;
        }).join('')}
      </tbody>
    </table>
  </div>
  <div style="padding:10px 16px;font-size:.75rem;color:var(--text-muted,#567);border-top:1px solid var(--border,#182433)">
    ${sorted.length} trofeo${sorted.length!==1?'s':''} · Hacé click en una fila para ver detalles
  </div>`;
}

window.wkOpenDet = async (id) => {
  const modal = document.getElementById('wkMDetail');
  const content = document.getElementById('wkDetailContent');
  if(!modal||!content) return;
  content.innerHTML = '<div class="wk-ld"><div class="wk-sp"></div></div>';
  modal.classList.add('open');
  try {
    const snap = await getDoc(doc(db,'trofeosPendientes',id));
    if(!snap.exists()){ content.innerHTML='<div class="wk-empty"><div class="wk-ei">❌</div><div class="wk-et">No encontrado</div></div>'; return; }
    const t = {id:snap.id,...snap.data()};
    // Increment views
    try{ updateDoc(doc(db,'trofeosPendientes',id),{views:increment(1)}); }catch(e){}
    const imgs = Array.isArray(t.images)&&t.images.length?t.images:[];
    content.innerHTML = `
      <div style="font-family:'Orbitron',monospace;font-size:1.4rem;font-weight:900;color:#ffd700;margin-bottom:4px">${wkEsc(t.fish||'Trofeo')}</div>
      <div style="font-family:'Orbitron',monospace;font-size:2rem;font-weight:900;color:#ffd700;margin-bottom:14px;text-shadow:0 0 18px rgba(255,215,0,.3)">${fmtKg(t.weight||0)}</div>
      ${imgs.length?`
        <div style="width:100%;aspect-ratio:4/3;overflow:hidden;border-radius:12px;background:#060a0e;margin-bottom:8px;cursor:zoom-in" onclick="wkOpenLb('${imgs[0]}')">
          <img id="wkDetMainImg" src="${imgs[0]}" style="width:100%;height:100%;object-fit:cover" alt="${wkEsc(t.fish)}">
        </div>
        ${imgs.length>1?`<div style="display:flex;gap:5px;margin-bottom:12px">${imgs.map((img,i)=>`<div class="dth ${i===0?'on':''}" onclick="this.parentElement.querySelectorAll('.dth').forEach(x=>x.classList.remove('on'));this.classList.add('on');document.getElementById('wkDetMainImg').src='${img}'"><img src="${img}" alt=""></div>`).join('')}</div>`:''}
      `:'<div style="width:100%;height:180px;background:#101820;border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:4rem;margin-bottom:14px">🐟</div>'}
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:16px">
        <div><div style="font-size:.7rem;color:var(--muted,#567890);text-transform:uppercase;letter-spacing:.4px">Mapa</div><div style="font-weight:600;margin-top:2px">${wkEsc(t.map||'?')}</div></div>
        <div><div style="font-size:.7rem;color:var(--muted,#567890);text-transform:uppercase;letter-spacing:.4px">Técnica</div><div style="font-weight:600;margin-top:2px">${wkEsc(t.technique||'?')}</div></div>
        ${t.spot?`<div><div style="font-size:.7rem;color:var(--muted,#567890);text-transform:uppercase;letter-spacing:.4px">Spot</div><div style="font-weight:600;margin-top:2px">${wkEsc(t.spot)}</div></div>`:''}
        ${t.date?`<div><div style="font-size:.7rem;color:var(--muted,#567890);text-transform:uppercase;letter-spacing:.4px">Fecha</div><div style="font-weight:600;margin-top:2px">${t.date}</div></div>`:''}
      </div>
      ${t.description?`<div style="background:rgba(0,212,255,.04);border:1px solid rgba(0,212,255,.12);border-radius:8px;padding:12px;font-size:.85rem;line-height:1.6;margin-bottom:14px">${wkEsc(t.description)}</div>`:''}
      <div style="display:flex;align-items:center;gap:10px;padding:12px 0;border-top:1px solid var(--border,#182433);border-bottom:1px solid var(--border,#182433);margin-bottom:16px">
        <div class="av" style="width:42px;height:42px;font-size:1.1rem">${t.userPhoto?`<img src="${t.userPhoto}" alt="">`:(t.userNick||'?')[0].toUpperCase()}</div>
        <div style="flex:1"><div style="font-weight:700">${wkEsc(t.userNick||'Anónimo')}</div><div style="font-size:.72rem;color:var(--muted,#567890)">${t.date||''}</div></div>
        <button class="rxb" onclick="wkTogLike('${t.id}')">❤ ${t.likes||0}</button>
        <span style="font-size:.8rem;color:var(--muted,#567890)">👁 ${t.views||0}</span>
      </div>
      <div>
        <div style="font-family:'Orbitron',monospace;font-size:.78rem;font-weight:700;color:#00d4ff;margin-bottom:10px">💬 Comentarios</div>
        <div id="wkDetCmts"><div class="wk-ld"><div class="wk-sp"></div></div></div>
        ${window.CU?`<div style="display:flex;gap:8px;margin-top:10px">
          <input class="wk-fi" style="flex:1" id="wkCmtInput_${id}" placeholder="Escribí un comentario..." onkeydown="if(event.key==='Enter')wkPostCmt('${id}')">
          <button class="btn btn-p btn-sm" onclick="wkPostCmt('${id}')">Enviar</button>
        </div>`:'<div style="font-size:.8rem;color:var(--muted,#567890);margin-top:10px;text-align:center">Iniciá sesión para comentar</div>'}
      </div>`;
    // Load comments
    wkLoadComments(id);
  } catch(e){ content.innerHTML='<div class="wk-empty"><div class="wk-ei">⚠️</div><div class="wk-et">Error al cargar</div></div>'; }
};

async function wkLoadComments(tId) {
  const el = document.getElementById('wkDetCmts');
  if(!el) return;
  try {
    const snap = await getDocs(query(collection(db,'trofeosPendientes',tId,'comments'), orderBy('createdAt','asc'), limit(50)));
    const cmts = snap.docs.map(d=>({id:d.id,...d.data()}));
    if(!cmts.length){ el.innerHTML='<div style="font-size:.8rem;color:var(--muted,#567890);padding:10px 0">Sin comentarios aún · ¡Sé el primero!</div>'; return; }
    el.innerHTML = cmts.map(c=>`<div class="cmt-item">
      <div class="av" style="width:28px;height:28px;font-size:.75rem;flex-shrink:0">${c.userPhoto?`<img src="${c.userPhoto}" alt="">`:(c.userNick||'?')[0].toUpperCase()}</div>
      <div class="cmt-b"><div class="cmt-u">${wkEsc(c.userNick||'?')}</div><div class="cmt-t">${wkEsc(c.text||'')}</div></div>
    </div>`).join('');
  } catch(e){ el.innerHTML='<div style="font-size:.8rem;color:var(--muted,#567890)">Error al cargar comentarios</div>'; }
}

window.wkPostCmt = async (tId) => {
  if(!window.CU){ toast('Iniciá sesión para comentar','err'); return; }
  const inp = document.getElementById('wkCmtInput_'+tId);
  const text = (inp?.value||'').trim();
  if(!text) return;
  inp.value = '';
  try {
    await addDoc(collection(db,'trofeosPendientes',tId,'comments'),{
      userId:window.CU.id, userNick:window.CU.nick||'?', userPhoto:window.CU.av||'',
      text, createdAt:serverTimestamp()
    });
    await updateDoc(doc(db,'trofeosPendientes',tId),{commentCount:increment(1)});
    wkLoadComments(tId);
    toast('Comentario publicado ✅','ok');
  } catch(e){ toast('Error al comentar','err'); }
};

window.wkTogLike = async (tId) => {
  if(!window.CU){ toast('Iniciá sesión para reaccionar','err'); return; }
  try {
    const ref = doc(db,'trofeosPendientes',tId);
    const snap = await getDoc(ref);
    const t = snap.data();
    const reactions = t.reactions||{};
    const already = reactions[window.CU.id];
    if(already){ await updateDoc(ref,{[`reactions.${window.CU.id}`]:deleteField(),likes:increment(-1)}); }
    else { await updateDoc(ref,{[`reactions.${window.CU.id}`]:{emoji:'❤️',nick:window.CU.nick},likes:increment(1)}); }
  } catch(e){}
};

// Publish modal
window.wkOpenPublish = () => {
  if(!window.CU){ toast('Iniciá sesión para publicar','err'); return; }
  wkResetForm();
  document.getElementById('wkMPublish').classList.add('open');
  setTimeout(wkInitDropzone, 50);
};
window.wkCm = id => { document.getElementById(id)?.classList.remove('open'); };
window.wkResetForm = () => {
  ['wkPF','wkPW','wkPS','wkPDesc'].forEach(id=>{ const el=document.getElementById(id); if(el) el.value=''; });
  ['wkPM','wkPT'].forEach(id=>{ const el=document.getElementById(id); if(el) el.value=''; });
  const dt = document.getElementById('wkPDt');
  if(dt) dt.value = new Date().toISOString().split('T')[0];
  _wkImgs=[]; _wkEditId=null; wkPvRender();
  const err=document.getElementById('wkPubErr'); if(err) err.textContent='';
};

// File handling for publish form
window.wkHFiles = (files) => {
  Array.from(files).forEach(f=>{
    if(_wkImgs.length>=5) return;
    if(!f.type.startsWith('image/')) return;
    const reader=new FileReader();
    reader.onload=e=>{ _wkImgs.push({file:f,preview:e.target.result}); wkPvRender(); };
    reader.readAsDataURL(f);
  });
};

// Init drag & drop on dropzone
function wkInitDropzone(){
  const dz = document.getElementById('wkDropzone');
  if(!dz || dz._dzInited) return;
  dz._dzInited = true;
  dz.addEventListener('dragover', e=>{ e.preventDefault(); dz.classList.add('over'); });
  dz.addEventListener('dragleave', e=>{ if(!dz.contains(e.relatedTarget)) dz.classList.remove('over'); });
  dz.addEventListener('drop', e=>{
    e.preventDefault(); dz.classList.remove('over');
    if(e.dataTransfer?.files?.length) wkHFiles(e.dataTransfer.files);
  });
}
function wkPvRender(){
  const grid=document.getElementById('wkPvGrid');
  if(!grid) return;
  grid.innerHTML=_wkImgs.map((img,i)=>`<div class="wk-pvitem"><img src="${img.preview}" alt=""><button class="wk-pvrem" onclick="_wkImgs.splice(${i},1);wkPvRender()">✕</button></div>`).join('');
}

// Upload to Cloudinary
async function wkUploadCloudinary(file) {
  // Usa la misma función uploadImage que el resto de la app (preset wikipediarf4)
  return await uploadImage(file, 'trofeos');
}

// Submit trophy
window.wkSubmitTrophy = async () => {
  const fish=(document.getElementById('wkPF')?.value||'').trim();
  const weight=(document.getElementById('wkPW')?.value||'').trim();
  const map=document.getElementById('wkPM')?.value||'';
  const technique=document.getElementById('wkPT')?.value||'';
  const spot=(document.getElementById('wkPS')?.value||'').trim();
  const desc=(document.getElementById('wkPDesc')?.value||'').trim();
  const date=document.getElementById('wkPDt')?.value||new Date().toISOString().split('T')[0];
  const err=document.getElementById('wkPubErr');
  if(!fish||!weight||!map||!technique){ if(err) err.textContent='Completá los campos obligatorios *'; return; }
  if(isNaN(parseFloat(weight))||parseFloat(weight)<=0){ if(err) err.textContent='Peso inválido'; return; }
  const btn=document.getElementById('wkSubmitBtn');
  if(btn){ btn.disabled=true; btn.textContent='Subiendo...'; }
  if(err) err.textContent='';
  try {
    let imageUrls=[];
    if(_wkImgs.length > 0) {
      if(btn) btn.textContent = 'Subiendo fotos...';
      for(const img of _wkImgs){
        try{
          const url=await wkUploadCloudinary(img.file);
          if(url) imageUrls.push(url);
        }catch(e){
          if(err) err.textContent='Error subiendo imagen: '+e.message;
          if(btn){ btn.disabled=false; btn.textContent='🏆 Publicar Trofeo'; }
          return;
        }
      }
    }
    if(btn) btn.textContent = 'Guardando...';
    const data={
      fish, weight:parseFloat(weight), map, technique, spot, description:desc, date,
      images:imageUrls, status:'approved',
      userId:window.CU.id, userNick:window.CU.nick||'?', userPhoto:window.CU.av||'',
      userRole:window.CU.role||'novato', likes:0, views:0, commentCount:0,
      createdAt:serverTimestamp()
    };
    const newRef = await addDoc(collection(db,'trofeosPendientes'), data);
    // config/stats: incrementar totalTrophies
    try{ await setDoc(doc(db,'config','stats'),{totalTrophies: increment(1)},{merge:true}); }catch(e){}
    // config/lastTrophy: guardar resumen para el login (1 lectura en vez de toda la coleccion)
    try{
      await setDoc(doc(db,'config','lastTrophy'),{
        id: newRef.id,
        fish: fish,
        weight: parseFloat(weight),
        map: map,
        nick: window.CU.nick||'?',
        imageUrl: imageUrls[0]||'',
        createdAt: new Date()
      });
    }catch(e){ console.warn('No se pudo actualizar config/lastTrophy:',e); }
    // Actualizar contador de trofeos del usuario
    try{ await updateDoc(doc(db,'users',window.CU.id),{trophyCount:increment(1)}); }catch(e){}
    // ── AUTO PREMIUM 15 DÍAS: si llega a 5 trofeos aprobados ──
    try{
      if(window.CU.role !== 'premium'){
        const _tSnap = await getDocs(query(
          collection(db,'trofeosPendientes'),
          where('userId','==',window.CU.id),
          where('status','==','approved')
        ));
        if(_tSnap.size >= 5){
          const _premExpiry = new Date();
          _premExpiry.setDate(_premExpiry.getDate() + 15);
          await updateDoc(doc(db,'users',window.CU.id),{
            role: 'premium',
            premiumSince: new Date().toISOString(),
            premiumExpiry: _premExpiry.toISOString(),
            premiumReason: 'auto_5trofeos'
          });
          window.CU.role = 'premium';
          setTimeout(function(){
            toast('🏆⭐ ¡Felicitaciones! Por compartir 5 trofeos ganaste 15 días de Premium gratis. Al vencer podés renovarlo por $1/mes 🎣','ok');
          }, 1200);
        }
      }
    }catch(e){ console.warn('Auto premium error:',e); }
    // Notificar a todos los suscriptores
    try{ _notifyNewTrophy(fish, weight, window.CU.nick||'?', imageUrls[0]||''); }catch(e){}
    wkCm('wkMPublish'); wkResetForm();
    toast('🏆 ¡Trofeo publicado!','ok');
    _wkLoaded=false; wkLoadHome();
  } catch(e){ if(err) err.textContent='Error al publicar: '+e.message; }
  finally{ if(btn){ btn.disabled=false; btn.textContent='🏆 Publicar Trofeo'; } }
};

// Admin panel
window.wkRenderAdmin = async () => {
  if(!window.CU||(window.CU.nick!==WK_ADMIN&&window.CU.role!=='admin')){ toast('Acceso denegado','err'); return; }
  const tS=await getDocs(query(collection(db,'trofeosPendientes'), limit(200)));
  const all=tS.docs.map(d=>({id:d.id,...d.data()}));
  const pend=all.filter(t=>t.status==='pending');
  const appr=all.filter(t=>t.status==='approved');
  const rej=all.filter(t=>t.status==='rejected');
  const bdg=document.getElementById('wkPBdg'); if(bdg) bdg.textContent=pend.length;
  const aDash=document.getElementById('wkADash');
  if(aDash) aDash.innerHTML=`<h3 style="font-family:'Orbitron',monospace;font-size:.95rem;color:#00d4ff;margin-bottom:14px">Dashboard</h3>
    <div class="asgrid">
      <div class="asc"><div class="asn">${appr.length}</div><div class="asl">Aprobados</div></div>
      <div class="asc"><div class="asn">${pend.length}</div><div class="asl">Pendientes</div></div>
      <div class="asc"><div class="asn">${rej.length}</div><div class="asl">Rechazados</div></div>
      <div class="asc"><div class="asn">${all.length}</div><div class="asl">Total</div></div>
    </div>`;
  const aPend=document.getElementById('wkAPend');
  if(aPend) aPend.innerHTML=pend.length===0?'<div class="wk-empty"><div class="wk-ei">✅</div><div class="wk-et">Sin pendientes</div></div>':pend.map(t=>`
    <div style="background:var(--bg,#060a0e);border:1px solid var(--border,#182433);border-radius:8px;padding:13px;margin-bottom:9px">
      <div style="display:flex;gap:10px;align-items:flex-start">
        ${t.images&&t.images[0]?`<img src="${t.images[0]}" style="width:64px;height:64px;object-fit:cover;border-radius:6px;flex-shrink:0">`:`<div style="width:64px;height:64px;background:#151f2a;border-radius:6px;display:flex;align-items:center;justify-content:center;font-size:1.6rem;flex-shrink:0">🐟</div>`}
        <div style="flex:1">
          <div style="font-weight:700">${wkEsc(t.fish)} — ${fmtKg(t.weight||0)}</div>
          <div style="font-size:.8rem;color:var(--muted,#567890)">${wkEsc(t.map)} · ${wkEsc(t.technique)} · por <strong>${wkEsc(t.userNick||'?')}</strong></div>
          ${t.description?`<div style="font-size:.78rem;color:var(--muted,#567890);margin-top:3px">${wkEsc(t.description.substring(0,100))}...</div>`:''}
        </div>
      </div>
      <div style="display:flex;gap:8px;margin-top:10px">
        <button class="btn btn-p btn-sm" onclick="wkApproveTrophy('${t.id}')">✅ Aprobar</button>
        <button class="btn btn-sm" style="background:#ff4466;color:#fff" onclick="wkRejectTrophy('${t.id}')">❌ Rechazar</button>
        <button class="btn btn-sm" style="background:#1877f2;color:#fff" onclick="wkEditTrophy('${t.id}')">✏️ Editar</button>
        <button class="btn btn-sm" style="background:#333;color:#aaa" onclick="wkDeleteTrophy('${t.id}')">🗑 Borrar</button>
      </div>
    </div>`).join('');
  const aAllP=document.getElementById('wkAAllP');
  if(aAllP) aAllP.innerHTML=`<div style="overflow-x:auto"><table class="atable">
    <thead><tr><th>Pez</th><th>Peso</th><th>Pescador</th><th>Mapa</th><th>Estado</th><th>Acciones</th></tr></thead>
    <tbody>${all.slice(0,50).map(t=>`<tr>
      <td>${wkEsc(t.fish)}</td><td>${fmtKg(t.weight||0)}</td>
      <td>${wkEsc(t.userNick||'?')}</td><td style="font-size:.8rem">${wkEsc(t.map||'?')}</td>
      <td><span class="status-badge status-${t.status}" style="position:static;display:inline">${t.status}</span></td>
      <td style="display:flex;gap:5px">
        ${t.status!=='approved'?`<button class="btn btn-p btn-xs" onclick="wkApproveTrophy('${t.id}')">✅</button>`:''}
        ${t.status!=='rejected'?`<button class="btn btn-xs" style="background:#ff4466;color:#fff" onclick="wkRejectTrophy('${t.id}')">❌</button>`:''}
        <button class="btn btn-xs" style="background:#1877f2;color:#fff" onclick="wkEditTrophy('${t.id}')">✏️</button>
        <button class="btn btn-xs" style="background:#333;color:#aaa" onclick="wkDeleteTrophy('${t.id}')">🗑</button>
      </td>
    </tr>`).join('')}</tbody>
  </table></div>`;
};

window.wkSwA = (el,sec) => {
  document.querySelectorAll('#wk-admin .ami').forEach(i=>i.classList.remove('on'));
  document.querySelectorAll('#wk-admin .as').forEach(s=>s.classList.remove('on'));
  el.classList.add('on');
  const secEl=document.getElementById(sec);
  if(secEl) secEl.classList.add('on');
};

window.wkApproveTrophy = async (id) => {
  try{ await updateDoc(doc(db,'trofeosPendientes',id),{status:'approved'}); toast('Trofeo aprobado ✅','ok'); _wkLoaded=false; wkRenderAdmin(); }catch(e){ toast('Error','err'); }
};
window.wkRejectTrophy = async (id) => {
  try{ await updateDoc(doc(db,'trofeosPendientes',id),{status:'rejected'}); toast('Trofeo rechazado','ok'); _wkLoaded=false; wkRenderAdmin(); }catch(e){ toast('Error','err'); }
};
window.wkDeleteTrophy = async (id) => {
  if(!confirm('¿Borrar este trofeo permanentemente?')) return;
  try{ await deleteDoc(doc(db,'trofeosPendientes',id)); toast('Trofeo borrado','ok'); _wkLoaded=false; wkRenderAdmin(); }catch(e){ toast('Error','err'); }
};

// Lightbox
window.wkOpenLb = (src) => {
  const lb=document.getElementById('wkImgLightbox');
  const img=document.getElementById('wkLbImg');
  if(lb&&img){ img.src=src; lb.classList.add('open'); }
};

// Expose to window  
window.wkLoadHome=wkLoadHome;
window.wkUpdateBannerCounts=wkUpdateBannerCounts;


// ── EDITAR TROFEO (Admin) ──
window.wkEditTrophy = async (id) => {
  const snap = await getDoc(doc(db,'trofeosPendientes',id));
  if(!snap.exists()){ toast('Trofeo no encontrado','err'); return; }
  const t = {id:snap.id,...snap.data()};
  const old = document.getElementById('_wkEditModal');
  if(old) old.remove();
  const MAPS = ['Belaya River','Volkhov River','Akhtuba River','Winding Rivulet','Old Burg Lake','Sura River','Ladoga Lake','Amber Lake','Bear Lake','Mosquito Lake','Seversky Donets','Yama River','Archipiélago Ladoga','Mar de Noruega','Lago Elk','Kuori','Cooper Lake','Río Tunguska'];
  const TECHS = ['Spinning','Fondo','Flote','Hielo','Jigging','Feeder','Match','Curricán','Pirking Fuerte','Movimiento en el Fondo','Fly','Collar','Pasternoster'];
  const STATUSES = ['pending','approved','rejected'];
  const m = document.createElement('div');
  m.id = '_wkEditModal';
  m.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.85);display:flex;align-items:center;justify-content:center;padding:16px;';
  m.innerHTML =
    '<div style="background:#161b22;border:1px solid #30363d;border-radius:14px;width:100%;max-width:560px;max-height:90vh;overflow-y:auto;padding:24px;position:relative;">' +
    '<button onclick="document.getElementById(\'_wkEditModal\').remove()" style="position:absolute;top:12px;right:14px;background:none;border:none;color:#8b949e;font-size:1.3rem;cursor:pointer;">✕</button>' +
    '<div style="font-family:\'Orbitron\',monospace;font-size:1rem;font-weight:800;color:#00d4ff;margin-bottom:18px;">✏️ Editar Trofeo</div>' +
    '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px;">' +
      '<div><label style="font-size:.78rem;color:#8b949e;display:block;margin-bottom:4px;">Pez *</label><input id="_weF" class="wk-fi" value="' + wkEsc(t.fish||'') + '" style="width:100%;"></div>' +
      '<div><label style="font-size:.78rem;color:#8b949e;display:block;margin-bottom:4px;">Peso (kg) *</label><input id="_weW" class="wk-fi" type="number" step="0.001" value="' + (t.weight||'') + '" style="width:100%;"></div>' +
    '</div>' +
    '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px;">' +
      '<div><label style="font-size:.78rem;color:#8b949e;display:block;margin-bottom:4px;">Mapa *</label><select id="_weM" class="wk-fi" style="width:100%;">' + MAPS.map(mp=>'<option value="'+mp+'"'+(t.map===mp?' selected':'')+'>'+mp+'</option>').join('') + '</select></div>' +
      '<div><label style="font-size:.78rem;color:#8b949e;display:block;margin-bottom:4px;">Técnica *</label><select id="_weT" class="wk-fi" style="width:100%;">' + TECHS.map(tc=>'<option value="'+tc+'"'+(t.technique===tc?' selected':'')+'>'+tc+'</option>').join('') + '</select></div>' +
    '</div>' +
    '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px;">' +
      '<div><label style="font-size:.78rem;color:#8b949e;display:block;margin-bottom:4px;">Spot</label><input id="_weS" class="wk-fi" value="' + wkEsc(t.spot||'') + '" style="width:100%;"></div>' +
      '<div><label style="font-size:.78rem;color:#8b949e;display:block;margin-bottom:4px;">Estado</label><select id="_weSt" class="wk-fi" style="width:100%;">' + STATUSES.map(s=>'<option value="'+s+'"'+(t.status===s?' selected':'')+'>'+s+'</option>').join('') + '</select></div>' +
    '</div>' +
    '<div style="margin-bottom:10px;"><label style="font-size:.78rem;color:#8b949e;display:block;margin-bottom:4px;">Descripción</label><textarea id="_weD" class="wk-fi" style="width:100%;min-height:70px;">' + wkEsc(t.description||t.notes||'') + '</textarea></div>' +
    '<div id="_weErr" style="color:#ff4466;font-size:.8rem;margin-bottom:8px;"></div>' +
    '<button onclick="wkSaveEdit(\'' + t.id + '\')" style="width:100%;background:#1877f2;color:#fff;border:none;border-radius:8px;padding:11px;font-weight:700;cursor:pointer;font-family:\'Exo 2\',sans-serif;font-size:.9rem;">💾 Guardar cambios</button>' +
    '</div>';
  m.addEventListener('click', e=>{ if(e.target===m) m.remove(); });
  document.body.appendChild(m);
};

window.wkSaveEdit = async (id) => {
  const fish = document.getElementById('_weF')?.value.trim();
  const weight = parseFloat(document.getElementById('_weW')?.value);
  const map = document.getElementById('_weM')?.value;
  const technique = document.getElementById('_weT')?.value;
  const spot = document.getElementById('_weS')?.value.trim();
  const status = document.getElementById('_weSt')?.value;
  const description = document.getElementById('_weD')?.value.trim();
  const err = document.getElementById('_weErr');
  if(!fish||!map||!technique||isNaN(weight)||weight<=0){ if(err) err.textContent='Completá los campos obligatorios'; return; }
  try{
    await updateDoc(doc(db,'trofeosPendientes',id),{fish,weight,map,technique,spot,description,status});
    document.getElementById('_wkEditModal')?.remove();
    toast('✅ Trofeo actualizado','ok');
    _wkLoaded=false; wkRenderAdmin();
  }catch(e){ if(err) err.textContent='Error: '+e.message; }
};


